// OPT-004: Check Cache (SEC-07 Hardened + OPT-039 Enhanced + OPT-D: Mode Parameter)
// SEC-07: Unicode-aware normalization + hash-based collision resistance

const input = $input.first().json;
const query = input.body?.chatInput || input.chatInput;

// EDGE-11: Recursive sub-workflow guard
const callDepth = input._call_depth || input.body?._call_depth || 0;
if (callDepth > 3) {
  return {
    json: {
      output: 'Internal error: recursive workflow call detected. Please try again.',
      sources: [],
      _error: 'recursive_call_depth_exceeded',
      _call_depth: callDepth
    }
  };
}


if (!query) {
  return { json: { ...input, _cache_status: 'no_query' } };
}

// OPT-D: Read mode parameter from webhook body
const mode = input.body?.mode || input.mode || '';
const validModes = ['fast', 'thinking', 'deep_research'];
const normalizedMode = validModes.includes(mode) ? mode : '';

// Check for cache bypass flag
const bypassCache = input.bypass_cache === true || input.body?.bypass_cache === true;

if (bypassCache) {
  return {
    json: {
      ...input,
      _cache_status: 'miss',
      _cache_bypassed: true,
      _mode: normalizedMode,
      chatInput: query
    }
  };
}

// SEC-07: Hardened cache key generation
// Keeps word-sort normalization for semantic matching (intentional)
// Adds hash suffix to prevent edge-case collisions
const normalizeQuery = (q) => {
  let normalized = q;
  try { normalized = q.normalize('NFC'); } catch (e) { }

  const semantic = normalized
    .toLowerCase()
    .trim()
    .replace(/[\u{1F600}-\u{1F6FF}\u{2600}-\u{2B55}\u{1F900}-\u{1F9FF}\u{1FA00}-\u{1FA6F}]/gu, '')
    .replace(/[^\p{L}\p{N}\s]/gu, '')
    .replace(/\s+/g, ' ')
    .split(' ')
    .filter(w => w.length > 2)
    .sort()
    .join('_')
    .substring(0, 80);

  // djb2 hash of original (pure JS, no crypto needed)
  const hashInput = normalized.toLowerCase().trim();
  let hash = 5381;
  for (let i = 0; i < hashInput.length; i++) {
    hash = ((hash << 5) + hash) + hashInput.charCodeAt(i);
    hash = hash & hash;
  }
  const hashHex = Math.abs(hash).toString(36);

  if (semantic.length < 3) return 'h_' + hashHex;
  return semantic.substring(0, 80) + '__' + hashHex;
};

const cacheKey = normalizeQuery(query);


// C-5: Redis cache read (Sprint 2) — falls back to staticData below
let redisHit = null;
try {
  const Redis = require('ioredis');
  const redis = new Redis({
    host: '127.0.0.1', port: 6379,
    password: $('env').first().json.REDIS_PASSWORD,
    connectTimeout: 1000,
    maxRetriesPerRequest: 0,
    lazyConnect: true
  });
  await redis.connect();
  const raw = await redis.get('ask:cache:' + cacheKey);
  await redis.quit();
  if (raw) {
    const entry = JSON.parse(raw);
    redisHit = {
      ...entry.response,
      _cache_status: 'hit',
      _cache_key: cacheKey,
      _cache_backend: 'redis',
      _cache_age_seconds: Math.floor((Date.now() - entry.timestamp) / 1000),
      _mode: normalizedMode,
      chatInput: chatInput
    };
  }
} catch (e) {
  // Redis not available — fall through to staticData
}

if (redisHit) {
  return [{ json: redisHit }];
}

// Get static data (persistent across executions)
const staticData = $getWorkflowStaticData('global');
const cache = staticData.cache || {};

// Check if cached and not expired
if (cache[cacheKey]) {
  const entry = cache[cacheKey];
  const now = Date.now();

  if (now < entry.expires) {
    return {
      json: {
        ...entry.response,
        _cache_status: 'hit',
        _cache_key: cacheKey,
        _cache_age_seconds: Math.floor((now - entry.timestamp) / 1000),
        _mode: normalizedMode,
      }
    };
  } else {
    delete cache[cacheKey];
    staticData.cache = cache;
  }
}

// Cache miss
return {
  json: {
    ...input,
    chatInput: query,
    _cache_status: 'miss',
    _cache_key: cacheKey,
    _mode: normalizedMode,
  }
};

// OPT-004: Format Cached Response
// Returns cached response directly to webhook — with NDJSON support
// EDGE-02: Source URL validation on cached responses

const input = $input.first().json;

// EDGE-02: Trusted domain list
const TRUSTED_DOMAINS = [
  'inc42.com', 'crunchbase.com', 'tracxn.com', 'linkedin.com',
  'wikipedia.org', 'economictimes.com', 'livemint.com',
  'moneycontrol.com', 'reuters.com', 'bloomberg.com',
  'techcrunch.com', 'yourstory.com', 'entrackr.com',
  'forbes.com', 'business-standard.com', 'ndtv.com',
  'cnbctv18.com', 'vccircle.com', 'dealstreetasia.com',
  'rbi.org.in', 'sebi.gov.in', 'mca.gov.in'
];

function validateSource(source) {
  if (typeof source === 'string') return source;
  if (typeof source !== 'object' || source === null) return source;
  const url = source.uri || source.url || '';
  if (!url || !url.startsWith('http')) return source;
  try {
    const hostname = new URL(url).hostname.replace(/^www\./, '');
    const isTrusted = TRUSTED_DOMAINS.some(d => hostname === d || hostname.endsWith('.' + d));
    if (isTrusted) return source;
    const cleaned = { title: source.title || 'Source' };
    if (source.source) cleaned.source = source.source;
    return cleaned;
  } catch (e) {
    const cleaned = { title: source.title || 'Source' };
    if (source.source) cleaned.source = source.source;
    return cleaned;
  }
}

const rawSources = input.sources || [];
const validatedSources = rawSources.map(validateSource);

const clean = {
  output: input.output || '',
  sources: validatedSources,
  fallback_used: input.fallback_used || false,
  raw_results: input.raw_results || null,
};

if (input.chatInput) clean.chatInput = input.chatInput;
if (input.suggestions) clean.suggestions = input.suggestions;


// EDGE-10: Cache age indicator
const ageSeconds = input._cache_age_seconds || 0;
let ageLabel;
if (ageSeconds < 60) ageLabel = 'just now';
else if (ageSeconds < 3600) ageLabel = Math.floor(ageSeconds / 60) + ' minutes ago';
else ageLabel = Math.floor(ageSeconds / 3600) + ' hours ago';
clean._cache_hit = true;
clean.cache_info = { from_cache: true, cached_at: ageLabel, age_seconds: ageSeconds };

// === NDJSON Generation ===
const ndjsonLines = [];
ndjsonLines.push(JSON.stringify({type: 'status', status: 'complete', query: clean.chatInput || ''}));

const text = clean.output || '';
const sections = text.split(/\n(?=##\s)/).filter(s => s.trim());
if (sections.length > 1) {
  sections.forEach((section, idx) => {
    ndjsonLines.push(JSON.stringify({type: 'result_chunk', index: idx, content: section.trim()}));
  });
} else {
  const paragraphs = text.split(/\n\n+/).filter(p => p.trim());
  if (paragraphs.length > 1) {
    paragraphs.forEach((para, idx) => {
      ndjsonLines.push(JSON.stringify({type: 'result_chunk', index: idx, content: para.trim()}));
    });
  } else {
    ndjsonLines.push(JSON.stringify({type: 'result_chunk', index: 0, content: text.trim()}));
  }
}

ndjsonLines.push(JSON.stringify({
  type: 'metadata',
  sources: clean.sources || [],
  suggestions: clean.suggestions || [],
  cache_status: 'hit'
}));

clean._ndjson = ndjsonLines.join('\n') + '\n';

return [{ json: clean }];

// OPT-120 + OPT-128 + OPT-130 + OPT-144: Query Classifier with Out-of-Scope Detection
// Routes queries to the best agent and signals which tools to prioritize.
// OPT-144: Detects clearly out-of-scope queries before ecosystem classification.
const inputData = $input.first().json;
const chatInput = inputData.chatInput || inputData.body?.chatInput || "";
const queryLower = chatInput.toLowerCase().trim();

// ============================================================
// OPT-144: OUT-OF-SCOPE DETECTION (runs FIRST)
// ============================================================

const outOfScopeKeywords = [
  "weather", "temperature", "forecast", "humidity", "rainfall", "climate today",
  "cricket", "football", "soccer", "tennis", "ipl score", "match score", "sports score",
  "recipe", "cooking", "how to cook", "ingredients for",
  "movie", "film review", "box office", "bollywood gossip",
  "election result", "political party", "prime minister", "parliament",
  "traffic jam", "road condition", "train schedule", "flight status",
  "hotel booking", "restaurant near", "tourist places",
  "horoscope", "zodiac", "astrology",
  "weight loss", "diet plan", "gym workout",
  "song lyrics", "music video"
];

// Startup/business keywords that override out-of-scope detection
const startupOverrideKeywords = [
  "startup", "funding", "investor", "venture", "unicorn", "ipo",
  "series a", "series b", "seed round", "valuation", "acquisition",
  "fintech", "edtech", "healthtech", "saas", "ecommerce", "d2c",
  "founder", "ceo", "portfolio", "datalabs", "inc42",
  "business model", "revenue", "profitable", "burn rate",
  "company", "companies", "platform", "app", "tech", "technology",
  "digital", "online", "b2b", "b2c", "marketplace",
  "profit", "loss", "turnover", "scale", "growth",
  "raised", "investment", "market",
  "market cap", "fundraise", "angel investor"
];

const hasOutOfScopeKw = outOfScopeKeywords.some(kw => queryLower.includes(kw));
const hasStartupOverride = startupOverrideKeywords.some(kw => queryLower.includes(kw));
// EDGE-06: Business context co-occurrence — second safety net
const businessContextWords = [
  "company", "companies", "startup", "startups", "platform", "app",
  "funding", "raised", "investor", "investment", "market", "business",
  "revenue", "profit", "growth", "scale", "series", "valuation",
  "ipo", "acquisition", "tech", "founded", "founder", "ceo",
  "enterprise", "venture", "sector", "industry"
];
const hasBusinessContext = businessContextWords.some(w => queryLower.includes(w));
const isOutOfScope = hasOutOfScopeKw && !hasStartupOverride && !hasBusinessContext;

// If out-of-scope, short-circuit classification
if (isOutOfScope) {
  return {
    body: inputData.body || { chatInput: chatInput },
    chatInput: chatInput,
    isEcosystemQuery: "false",
    isOutOfScope: "true",
    classifiedAs: "out_of_scope",
    queryType: "out_of_scope",
    toolPriority: [],
    _classification_version: "OPT-144"
  };
}

// ============================================================
// KEYWORD DICTIONARIES (unchanged from OPT-130)
// ============================================================

const ecosystemKeywords = [
  "ecosystem", "state of", "current state", "trends in", "how is the",
  "how are", "what is happening", "what are", "status of", "performing in",
  "is this", "something happening", "happening across", "across the",
  "industry wide", "industry-wide", "sector wide", "sector-wide",
  "market trend", "is there a trend",
  "are we seeing", "are there more", "are there fewer",
  "compare", "compared to", "comparison", "vs ", "versus",
  "across different", "across all", "across various", "across sectors",
  "which sectors", "in which sectors",
  "pivoted", "pivot", "how did", "how has", "what happened",
  "decline", "growth in", "funding in",
  "find", "search", "list", "show", "discover", "get",
  "which", "where", "how many", "how much", "what is the",
  "top ", "biggest", "largest", "fastest", "most funded", "highest",
  "recent", "latest", "new ", "emerging", "upcoming",
  "raised", "invested", "acquired", "merged", "ipo",
  "total funding", "funding round", "series a", "series b", "series c",
  "series d", "seed round", "pre-seed", "growth stage",
  "valuation", "revenue", "profitable", "profitability",
  "investors in", "backed by", "portfolio of",
  "analyze", "analysis", "overview of", "landscape",
  "opportunities in", "challenges in", "outlook for"
];

const sectorKeywords = [
  "ai startup", "fintech", "edtech", "healthtech", "e-commerce", "ecommerce",
  "saas", "agritech", "logistics", "supply chain", "d2c", "b2b", "b2c",
  "sector", "vertical", "industry",
  "hr tech", "hrtech", "human resources", "cleantech", "clean tech",
  "proptech", "prop tech", "insurtech", "insuretech",
  "mediatech", "media tech", "legaltech", "legal tech",
  "foodtech", "food tech", "traveltech", "travel tech",
  "autotech", "auto tech", "spacetech", "space tech",
  "deeptech", "deep tech", "biotech", "gaming",
  "unicorn", "unicorns", "startup", "startups", "funding", "funded",
  "wealthtech", "neobank", "crypto", "blockchain", "web3", "ev",
  "electric vehicle", "drone", "robotics", "cybersecurity", "cloud",
  "marketplace", "social commerce", "quick commerce", "q-commerce"
];

const locationKeywords = [
  "bangalore", "bengaluru", "mumbai", "delhi", "ncr", "gurgaon", "gurugram",
  "pune", "hyderabad", "chennai", "kolkata", "noida", "india", "indian",
  "jaipur", "ahmedabad", "kochi", "thiruvananthapuram", "lucknow",
  "chandigarh", "indore", "bhubaneswar", "coimbatore", "vizag",
  "visakhapatnam", "nagpur", "surat", "tier 1", "tier 2", "tier 3",
  "metro", "non-metro"
];

const personKeywords = [
  "who is", "tell me about", "founder of", "ceo of", "cto of",
  "investor ", "angel investor", "venture capitalist",
  "co-founder", "cofounder", "managing director", "partner at",
  "board member", "chairman", "chairperson"
];

const comparisonKeywords = [
  "compare", "vs", "versus", "compared to", "difference between",
  "better than",
  "against", "head to head", "side by side"
];

// ============================================================
// KEYWORD MATCHING
// ============================================================

const hasEcosystemKeyword = ecosystemKeywords.some(kw => queryLower.includes(kw));
const hasSectorKeyword = sectorKeywords.some(kw => queryLower.includes(kw));
const hasLocationKeyword = locationKeywords.some(kw => queryLower.includes(kw));
const hasPersonKeyword = personKeywords.some(kw => queryLower.includes(kw));
const hasComparisonKeyword = comparisonKeywords.some(kw => queryLower.includes(kw));

// ============================================================
// OPT-130: MULTI-SIGNAL CLASSIFICATION
// ============================================================

let queryType = "general";
let toolPriority = ["Inc42 Context", "Datalabs", "Inc42 Updates"];

if (hasPersonKeyword && !hasSectorKeyword) {
  queryType = "person";
  toolPriority = ["Inc42 Context", "Inc42 Updates", "Datalabs"];
}
else if (hasSectorKeyword && hasLocationKeyword) {
  queryType = "search";
  toolPriority = ["Datalabs", "Inc42 Context", "Inc42 Updates"];
}
else if (hasComparisonKeyword) {
  queryType = "comparison";
  toolPriority = ["Datalabs", "Inc42 Context", "Inc42 Updates"];
}
else if (hasEcosystemKeyword && hasSectorKeyword) {
  queryType = "sector";
  toolPriority = ["Inc42 Updates", "Datalabs", "Inc42 Context"];
}
else if (/\b[A-Z][a-z]+(?:\s+[A-Z][a-z]+)*\b/.test(chatInput) && !hasSectorKeyword) {
  queryType = "company";
  toolPriority = ["Inc42 Context", "Datalabs", "Inc42 Updates"];
}

// ============================================================
// OPT-128 + OPT-130: EXPANDED ECOSYSTEM CLASSIFICATION
// ============================================================
const isEcosystemQuery =
  (hasEcosystemKeyword && hasSectorKeyword) ||
  (hasSectorKeyword && hasLocationKeyword) ||
  (hasComparisonKeyword) ||
  (hasPersonKeyword) ||
  (hasEcosystemKeyword && hasLocationKeyword);

return {
  body: inputData.body || { chatInput: chatInput },
  chatInput: chatInput,
  isEcosystemQuery: isEcosystemQuery ? "true" : "false",
  isOutOfScope: "false",
  classifiedAs: isEcosystemQuery ? "ecosystem" : "other",
  queryType: queryType,
  toolPriority: toolPriority,
  _classification_version: "OPT-144"
};

// OPT-073: Hardened decomposer parse response
// OPT-077: Post-LLM decomposer constraints (advisory override, sub-query caps)
// Handles multiple response structures with fallback to simple query path
try {
  let text = "";
  const input = $input.first().json;

  // Try multiple response structures
  if (input.output && Array.isArray(input.output) && input.output[0]?.content?.[0]?.text) {
    // Standard OpenAI format
    text = input.output[0].content[0].text;
  } else if (typeof input.output === 'string') {
    // Direct string output
    text = input.output;
  } else if (input.message?.content) {
    // Alternative message format
    text = typeof input.message.content === 'string'
      ? input.message.content
      : JSON.stringify(input.message.content);
  } else if (input.text) {
    // Plain text field
    text = input.text;
  } else if (input.response) {
    // Response field
    text = typeof input.response === 'string' ? input.response : JSON.stringify(input.response);
  } else {
    // Cannot parse — fall through to catch block
    throw new Error("Unrecognized response structure: " + JSON.stringify(Object.keys(input)));
  }

  // Remove ```json and ``` wrappers
  text = text.replace(/```json|```/g, '').trim();

  // Parse JSON
  const parsed = JSON.parse(text);

  // ========================================
  // OPT-077: Hard decomposer constraints (post-LLM enforcement)
  // Applied AFTER LLM classification to catch cases where prompt hints are ignored.
  // The decomposer LLM sometimes ignores "max 3 sub-queries" and "advisory = SIMPLE"
  // hints, causing timeouts from sequential sub-query execution.
  // ========================================

  // Get original query for pattern matching
  let chatInput_077 = "";
  try {
    // OPT-155c: Read resolved query first (pronoun resolution)
    chatInput_077 = $("OPT-155c: Query Resolver").first().json.chatInput || "";
  } catch (e155c) {}
  if (!chatInput_077) {
  try {
    chatInput_077 = $("Webhook").first().json.body?.chatInput
      || $("Webhook").first().json.chatInput
      || "";
  } catch (e077) {
    try {
      chatInput_077 = $("When chat message received").first().json.chatInput || "";
    } catch (e077b) {
      chatInput_077 = "";
    }
  }
  }
  const originalQuery = chatInput_077.toLowerCase();

  // Rule 1: Advisory query override — force SIMPLE
  // These queries seek opinions/advice, not data. Route to Inc42 Context, not decompose.
  const advisoryPatterns = [
    /\b(build vs buy|buy vs build)\b/i,
    /\b(how to|how should|how do|how can)\b.*\b(scale|grow|improve|build|manage|handle|approach)\b/i,
    /\b(best practices|strategies for|tips for|advice on)\b/i,
    /\b(when should|should i|should we|is it better)\b/i,
    /\b(pros and cons|advantages|disadvantages)\b/i,
  ];
  const isAdvisory = advisoryPatterns.some(p => p.test(originalQuery));
  if (isAdvisory && parsed.is_complex) {
    parsed.is_complex = false;
    parsed._opt077_override = "advisory_to_simple";
  }

  // Rule 2: Sub-query count cap — max 3
  // Sequential execution of 4+ sub-queries at ~20-30s each exceeds 120s timeout.
  if (parsed.simple_queries && parsed.simple_queries.length > 3) {
    parsed._opt077_original_count = parsed.simple_queries.length;
    parsed.simple_queries = parsed.simple_queries.slice(0, 3);
    parsed._opt077_truncated = true;
  }

  // Rule 3: Year comparison cap — max 2 sub-queries
  // "2024 vs 2023" needs at most 2 queries (one per year), not N per sector.
  const yearComparisonPattern = /\b(20\d{2})\b.*\b(vs|versus|compared to|comparison)\b.*\b(20\d{2})\b/i;
  if (yearComparisonPattern.test(originalQuery) && parsed.simple_queries && parsed.simple_queries.length > 2) {
    parsed._opt077_original_count = parsed._opt077_original_count || parsed.simple_queries.length;
    parsed.simple_queries = parsed.simple_queries.slice(0, 2);
    parsed._opt077_override = "year_comparison_cap";
  }

  // Rule 4: Top-N ranking override — force SIMPLE (OPT-078)
  // "Top 5 funded FinTech", "Top 10 largest startups", etc. are single sorted searches
  // Decomposer creates N entity-specific sub-queries causing timeouts
  const topNPattern = /top\s+\d+\s+(funded|largest|biggest|most|highest|fastest|richest|valued|active|prominent)/i;
  const topNRankingPattern = /top\s+\d+/i;
  const topNListPattern = /\b(funded|largest|biggest|most funded|highest funded|fastest growing|most valued|most active)\b/i;
  if ((topNPattern.test(originalQuery) || (topNRankingPattern.test(originalQuery) && topNListPattern.test(originalQuery))) && parsed.is_complex) {
    parsed.is_complex = false;
    parsed._opt078_override = "top_n_to_simple";
    // Rewrite sub-queries to single sorted search
    if (parsed.simple_queries && parsed.simple_queries.length > 1) {
      parsed._opt078_original_queries = parsed.simple_queries.length;
      parsed.simple_queries = [{
        query: chatInput_077,
        entity: "search",
        entity_type: "search",
        data_query: "sorted_search"
      }];
    }
  }

  // Rule 5: Broad "all X" or "list X" override — force SIMPLE (OPT-078)
  // "All FinTech unicorns", "List all funded companies" = single search
  const allListPattern = /\b(all|list|show me all|give me all|every)\b.*\b(unicorn|startup|compan|funded|investor)/i;
  if (allListPattern.test(originalQuery) && parsed.is_complex && !originalQuery.includes(' vs ') && !originalQuery.includes(' versus ') && !originalQuery.includes(' compare ')) {
    parsed.is_complex = false;
    parsed._opt078_override = "all_list_to_simple";
  }

  // Rule 5.5: Year-comparison override — force COMPLEX with structured sub-queries (BLOCK1-PIPELINE-001)
  // Fixes OPT-084/106 conflict: Rule 6 was firing before Rule 8 for year-comparison queries,
  // preventing structured year-specific sub-queries. Now year comparisons ALWAYS get 2 sub-queries.
  const yearCompFix = originalQuery.match(/\b(20\d{2})\b.*\b(vs\.?|versus|compared?\s+to|in\s+comparison|than|from)\b.*\b(20\d{2})\b/i)
    || originalQuery.match(/\b(decline|declining|growth|growing|increasing|decreasing)\b.*\b(20\d{2})\b.*\b(compared|vs|than|from)\b.*\b(20\d{2})\b/i);

  if (yearCompFix) {
    // Extract the two years
    const allYears = [...originalQuery.matchAll(/\b(20\d{2})\b/g)].map(m => m[1]);
    if (allYears.length >= 2) {
      const year1 = allYears[0];
      const year2 = allYears[allYears.length - 1];
      // Extract topic (everything except years and comparison words)
      const topic = originalQuery
        .replace(/\b20\d{2}\b/g, '')
        .replace(/\b(vs\.?|versus|compared?\s+to|comparison|than|from|in|and|which|are\s+we\s+seeing|more|fewer|less|higher|lower|increase|decrease|decline|growth)\b/gi, '')
        .replace(/\s+/g, ' ')
        .trim();

      parsed.is_complex = true;
      parsed.simple_queries = [
        { query: topic + ' ' + year1, entity: topic, entity_type: 'search', data_query: 'year_trend', _trend_year: year1 },
        { query: topic + ' ' + year2, entity: topic, entity_type: 'search', data_query: 'year_trend', _trend_year: year2 }
      ];
      parsed.aggregation_type = 'compare';
      parsed._block1_override = "year_comparison_forced_complex";
      parsed._block1_years = [year1, year2];
    }
  }

  // Rule 6: Narrative/advisory query detection — force SIMPLE (OPT-084)
  // Catches queries seeking stories, lessons, advice that data tools can't answer
  const narrativePatterns = [
    // OPT-113: Fixed — allow intervening adjectives between "which" and "startups"
    /which\s+(?:\w+\s+)*?(startups?|companies?)\s+(?:\w+\s+)*?(pivoted|changed|shifted|failed|succeeded|grew)/i,
    /\b(approach|strategy|framework|methodology|playbook)\b/i,
    /how\s+did\s+.*\s+(evolve|change|transform|grow|develop|scale|succeed|fail)/i,
    /\b(pivot|pivoted|pivoting)\s+(from|story|stories|example)/i,
    /\b(lessons?|learnings?|takeaways?)\s+from/i,
    /\b(common\s+challenges?|common\s+mistakes?|common\s+pitfalls?)\b/i,
    /\b(success\s+stor|failure\s+stor|pivot\s+stor)/i,
    /what\s+(can|should|do)\s+.*\s+learn/i,
    /\b(salary|salaries|compensation|pay)\s.*(engineer|developer|designer|manager)/i,
    /\b(tech\s+stack|technology\s+stack)\b/i,
    /how\s+(to|should|do|can)\s+(build|create|start|launch|design|implement)\b/i,
    // OPT-113: Comparison/temporal patterns — force simple for "2025 vs 2024" type queries
    /\b(vs\.?|versus|compared?\s+to|in\s+comparison)\b.*\d{4}/i,
    /\b(more|fewer|less|higher|lower|increase|decrease|decline|growth)\b.*\b(in|during)\s+\d{4}\b.*\b(vs|than|compared|from)\b/i,
    /\b\d{4}\s*(vs\.?|versus|compared?\s+to)\s*\d{4}\b/i,
  ];
  const isNarrative = narrativePatterns.some(p => p.test(originalQuery));
  if (isNarrative && parsed.is_complex) {
    parsed.is_complex = false;
    parsed._opt084_override = "narrative_to_simple";
  }

  // Rule 6.5: News/temporal query detection — force SIMPLE (OPT-132)
  // Simple news queries should go directly to Inc42 Updates, not decompose
  const newsPatterns = [
    /\b(latest|recent|breaking|new)\s+(?:\w+\s+)*?(news|updates|developments|articles)/i,
    /\b(news|updates|articles)\s+(from|in|during|about)\s+(january|february|march|april|may|june|july|august|september|october|november|december|\d{4})/i,
    /\bwhat('?s|\s+is)\s+happening\s+in\b/i,
  ];
  const isNewsQuery = newsPatterns.some(p => p.test(originalQuery));
  if (isNewsQuery && parsed.is_complex) {
    parsed.is_complex = false;
    parsed._opt132_override = "news_to_simple";
  }

  // Rule 7: Aggregation context preservation (OPT-085)
  // When decomposing comparisons or lists, attach context to sub-queries
  if (parsed.is_complex && parsed.aggregation_type && parsed.simple_queries) {
    const aggType = parsed.aggregation_type;
    parsed.simple_queries = parsed.simple_queries.map((sq, idx) => ({
      ...sq,
      _aggregation_context: aggType,
      _aggregation_instruction: aggType === 'compare'
        ? 'This is part ' + (idx + 1) + ' of a comparison query. Return structured data suitable for comparison.'
        : aggType === 'list'
        ? 'This is part of a list/ranking query. Return data with consistent fields for aggregation.'
        : null,
      _compare_with: aggType === 'compare' && idx > 0 ? 'sub_query_0' : null
    }));
    parsed._opt085_context_preserved = true;
  }

  // Rule 8: Trend query routing (OPT-106)
  // Handles "post-COVID", "X vs Y over time", and emerging category queries
  // These should either be SIMPLE or have structured year-specific sub-queries
  const postCovidPattern = /\b(post[- ]?covid|after covid|since covid|since the pandemic)\b/i;
  const emergingPattern = /\b(new|emerging|upcoming)\s+(startup\s+)?(categories|sectors|industries|verticals)\b/i;
  if ((postCovidPattern.test(originalQuery) || emergingPattern.test(originalQuery)) && parsed.is_complex) {
    parsed.is_complex = false;
    parsed._opt106_override = "trend_to_simple";
  }

  // For year-over-year trend queries that remain complex, structure sub-queries by year
  const yearTrendMatch = originalQuery.match(/\b(20\d{2})\b.*\b(vs|versus|compared to|comparison)\b.*\b(20\d{2})\b/i);
  if (yearTrendMatch && parsed.is_complex && parsed.simple_queries) {
    const year1 = yearTrendMatch[1];
    const year2 = yearTrendMatch[3];
    // Extract topic from query (everything except years and comparison words)
    const topic = originalQuery
      .replace(/\b20\d{2}\b/g, '')
      .replace(/\b(vs|versus|compared to|comparison|are we seeing|more|in|and|which)\b/gi, '')
      .trim();
    parsed.simple_queries = [
      { query: topic + ' ' + year1, entity: topic, entity_type: 'search', data_query: 'year_trend', _trend_year: year1 },
      { query: topic + ' ' + year2, entity: topic, entity_type: 'search', data_query: 'year_trend', _trend_year: year2 }
    ];
    parsed._opt106_override = "year_trend_structured";
    parsed._opt106_years = [year1, year2];
    parsed.aggregation_type = 'compare';
  }

  // OPT-101: Preserve chatInput in decomposer output for downstream nodes
  // Classify Query Type and AI Agent nodes need chatInput but decomposer output lacks it
  // OPT-155c: chatInput_077 now contains resolved query when available
  parsed.chatInput = chatInput_077;

  return [{ json: parsed }];

} catch (e) {
  // Fallback: treat original query as a simple (non-decomposed) query
  // Ralph R2: Smart entity detection instead of blind first-3-words
  let chatInput = "";
  try {
    // OPT-155c: Read resolved query first (pronoun resolution)
