  const isComparisonQuery = /\b(vs|versus|compared to|comparison|comparing)\b/i.test(queryLower);
  const isSectorQuery = /\b(agritech|fintech|edtech|healthtech|deeptech|cleantech|saas|d2c|ecommerce|logistics|ev)\b/i.test(queryLower);
  const isYoyQuery = /\b(20\d{2})\b.*\b(vs|versus|compared|than|from)\b/i.test(queryLower) || /\b(vs|versus|compared|than|from)\b.*\b(20\d{2})\b/i.test(queryLower);

  let entityType = "company";
  let entity = chatInput.split(" ").slice(0, 3).join(" ");
  let dataQuery = "general";

  if (isTrendQuery || isComparisonQuery || isSectorQuery || isYoyQuery) {
    entityType = "search";
    entity = chatInput;
    dataQuery = isYoyQuery ? "year_trend" : isSectorQuery ? "sector" : "general";
  }

  return [{ json: {
    is_complex: false,
    chatInput: chatInput,
    simple_queries: [{
      query: chatInput,
      entity: entity,
      entity_type: entityType,
      data_query: dataQuery
    }],
    _parse_fallback: true,
    _parse_error: e.message,
    _ralph_r2_fallback_type: entityType
  }}];
}

