// OPT-016 Phase 1: Extract Validation Criteria from Original Query
// Uses pattern matching to extract funding stage, sector, time window, etc.
// FIX: Parse AI Agent JSON string output to extract sources/raw_results

const items = $input.all();
const output = [];

// ========================================
// PARSE JSON FROM AI AGENT OUTPUT
// ========================================

function parseResponseJSON(response) {
  // If response.output is a string, try to parse it as JSON
  if (typeof response.output === 'string') {
    // Try direct JSON parse first (for AI Agent raw JSON output)
    try {
      const parsed = JSON.parse(response.output);
      return parsed;
    } catch (e) {
      // Fall through to markdown parsing
    }

    // Try markdown code block patterns as fallback
    const patterns = [
      /```json\s*\n([\s\S]*?)\n```/,  // Standard markdown
      /```json\s*([\s\S]*?)```/,        // No newlines
      /```\s*([\s\S]*?)```/             // No language tag
    ];

    for (const pattern of patterns) {
      const jsonMatch = response.output.match(pattern);
      if (jsonMatch && jsonMatch[1]) {
        try {
          const parsed = JSON.parse(jsonMatch[1].trim());
          return parsed;
        } catch (e) {
          // Try next pattern
          continue;
        }
      }
    }
  }
  return response;
}


