// Pattern definitions for criteria extraction
const FUNDING_STAGES = {
  patterns: [
    /\b(Series\s*[A-F]\+?)\b/i,
    /\b(Pre-?Seed|Seed|Pre-?Series\s*A|Bridge\s*Round?)\b/i,
    /\b(Early\s*Stage|Growth\s*Stage|Late\s*Stage)\b/i
  ],
  getField: (value) => {
    // Specific rounds use last_funding_type
    if (/Series|Seed|Pre-Series|Bridge/i.test(value)) {
      return 'last_funding_type';
    }
    // Lifecycle stages use last_funding_stage
    return 'last_funding_stage';
  }
};

const SECTORS = [
  'EdTech', 'FinTech', 'HealthTech', 'AgriTech', 'CleanTech',
  'FoodTech', 'PropTech', 'InsurTech', 'LegalTech', 'HRTech',
  'DeepTech', 'BioTech', 'MedTech', 'GreenTech', 'SpaceTech',
  'SaaS', 'B2B', 'B2C', 'D2C', 'E-commerce', 'Ecommerce',
  'Artificial Intelligence', 'AI', 'Machine Learning', 'ML',
  'Gaming', 'Media', 'Entertainment', 'Travel', 'Logistics',
  'Manufacturing', 'Retail', 'Fashion', 'Beauty', 'Wellness',
  'Education', 'Healthcare', 'Finance', 'Banking', 'Insurance',
  'Real Estate', 'Energy', 'Automotive', 'EV', 'Mobility'
];

const CITIES = [
  'Bangalore', 'Bengaluru', 'Mumbai', 'Delhi', 'NCR', 'Gurugram', 'Gurgaon',
  'Noida', 'Hyderabad', 'Chennai', 'Pune', 'Kolkata', 'Ahmedabad',
  'Jaipur', 'Kochi', 'Chandigarh', 'Indore', 'Coimbatore'
];

// Extract function
function extractCriteria(query) {
  const criteria = {};
  const notes = [];
  let confidence = 'none';

  if (!query) {
    return { criteria, confidence, notes: ['No query provided'] };
  }

  const queryLower = query.toLowerCase();

  // Extract funding stage
  for (const pattern of FUNDING_STAGES.patterns) {
    const match = query.match(pattern);
    if (match) {
      const value = match[1].replace(/\s+/g, ' ').trim();
      criteria.funding_stage = {
        field: FUNDING_STAGES.getField(value),
        value: value
      };
      notes.push('Extracted funding_stage: ' + value);
      confidence = 'high';
      break;
    }
  }

  // Extract sector
  for (const sector of SECTORS) {
    if (queryLower.includes(sector.toLowerCase())) {
      criteria.sector = { value: sector };
      notes.push('Extracted sector: ' + sector);
      if (confidence === 'none') confidence = 'medium';
      break;
    }
  }

  // Extract year/time window
  const yearMatch = query.match(/\b(20\d{2})\b/);
  if (yearMatch) {
    const year = parseInt(yearMatch[1]);
    criteria.time_window = {
      type: 'year_range',
      start: year,
      end: year
    };
    notes.push('Extracted year: ' + year);
    if (confidence === 'none') confidence = 'medium';
  }

  // Check for relative time (last X months, recent)
  const relativeMatch = query.match(/last\s*(\d+)\s*(months?|weeks?|days?)/i);
  if (relativeMatch && !criteria.time_window) {
    criteria.time_window = {
      type: 'relative',
      amount: parseInt(relativeMatch[1]),
      unit: relativeMatch[2].toLowerCase()
    };
    notes.push('Extracted relative time: last ' + relativeMatch[1] + ' ' + relativeMatch[2]);
    if (confidence === 'none') confidence = 'medium';
  }

  // Extract location/city
  for (const city of CITIES) {
    if (queryLower.includes(city.toLowerCase())) {
      criteria.location = { value: city };
      notes.push('Extracted location: ' + city);
      break;
    }
  }

  // Extract amount range (e.g., "over $10M", "above 50M")
  const amountMatch = query.match(/(over|above|more than|greater than|under|below|less than)\s*\$?\s*(\d+(?:\.\d+)?)(M|million|K|thousand)?/i);
  if (amountMatch) {
    const operator = amountMatch[1].toLowerCase();
    let amount = parseFloat(amountMatch[2]);
    const unit = (amountMatch[3] || '').toUpperCase();

    if (unit === 'M' || unit.includes('million')) amount *= 1000000;
    if (unit === 'K' || unit.includes('thousand')) amount *= 1000;

    criteria.amount_range = {
      field: 'last_funding_amount'
    };

    if (['over', 'above', 'more than', 'greater than'].includes(operator)) {
      criteria.amount_range.min = amount;
    } else {
      criteria.amount_range.max = amount;
    }
    notes.push('Extracted amount constraint: ' + operator + ' ' + amount);
  }

  // Determine overall confidence
  if (Object.keys(criteria).length >= 2) confidence = 'high';
  else if (Object.keys(criteria).length === 1) confidence = 'medium';
  else confidence = 'none';

  return { criteria, confidence, notes };
}

