// OPT-029: Enhanced Tool Bypass Detection (v4.1 - Fixed)
// Detects BOTH hard bypasses (no tools called) AND soft bypasses (tools called but no results)
// FIX: Removed empty_raw_results check which caused false positives for Inc42 Context/Updates
// Updated: November 27, 2025

const input = $input.all();
