function parseResponseJSON(response) {
  if (typeof response.output === 'string') {
    // Try direct JSON parse first
    try {
      const parsed = JSON.parse(response.output);
      return { ...response, ...parsed };
    } catch (e) {
      // Try markdown code block
      const jsonMatch = response.output.match(/```json\s*\n([\s\S]*?)\n```/);
      if (jsonMatch && jsonMatch[1]) {
        try {
          const parsed = JSON.parse(jsonMatch[1]);
          return { ...response, ...parsed };
        } catch (e2) {
          return response;
        }
      }
    }
  }
  return response;
}

const parsedResponse = parseResponseJSON(response);

// ========================================
// ENHANCED BYPASS DETECTION (OPT-029)
// ========================================

function detectToolBypass(response, metadata) {
  const bypasses = [];
  // Safe conversion of response.output to lowercase string
  let responseText = "";
  try {
    if (typeof response.output === "string") {
      responseText = response.output.toLowerCase();
    } else if (response.output != null && response.output !== undefined) {
      const stringified = JSON.stringify(response.output);
      responseText = typeof stringified === "string" ? stringified.toLowerCase() : "";
    }
  } catch (e) {
    responseText = "";
  }

  // ========================================
  // CHECK 1: Empty sources array (HARD BYPASS)
  // ========================================
  if (!response.sources || response.sources.length === 0) {
    bypasses.push({
      type: "sources_array_empty",
      confidence: "high",
      bypass_type: "hard",
      evidence: "No sources array populated"
    });
  }

  // ========================================
  // CHECK 2: Fast completion (HARD BYPASS indicator)
  // ========================================
  // V3: Relaxed threshold (multi-agent pipeline takes longer)
  // Tier 1.1: Skip fast-completion check when fan-out provided data
  const hasPrefetchedData = (response._prefetched_section_count || 0) > 0;
  if (metadata.duration < 8000 && !hasPrefetchedData) {
    bypasses.push({
      type: "fast_completion_no_tools",
      confidence: "high",
      bypass_type: "hard",
      evidence: `Completed in ${metadata.duration}ms (< 15s threshold)`
    });
  }

  // ========================================
  // CHECK 3: "No results" phrases (SOFT BYPASS)
  // Triggers when AI explicitly admits no data was found
  // ========================================
  const noResultsPhrases = [
    "no specific articles found",
    "specific articles did not surface",
    "no articles found",
    "did not find any",
    "couldn't find specific",
    "no relevant articles",
    "no data found",
    "no results found",
    "based on general knowledge",
    "general knowledge of",
    "widely recognized in discussions",
    "general trends observed"
  ];

  const phraseMatches = noResultsPhrases.filter(phrase =>
    responseText.includes(phrase.toLowerCase())
  );

  if (phraseMatches.length >= 2) {
    // Require 2+ phrase matches for soft bypass to reduce false positives
    bypasses.push({
      type: "no_results_admission",
      confidence: "high",
      bypass_type: "soft",
      evidence: `Found ${phraseMatches.length} "no results" phrases: ${phraseMatches.slice(0, 3).join(', ')}`
    });
  }

  // ========================================
  // CHECK 4: Disclaimer patterns (SOFT BYPASS)
  // ========================================
  const disclaimerPatterns = [
    /if specific .* are needed/i,
    /recommend exploring/i,
    /insights are based on general/i
  ];

  const disclaimerMatches = disclaimerPatterns.filter(pattern =>
    pattern.test(responseText)
  );

  if (disclaimerMatches.length >= 2) {
    // Require 2+ disclaimer matches
    bypasses.push({
      type: "disclaimer_detected",
      confidence: "medium",
      bypass_type: "soft",
      evidence: `Found ${disclaimerMatches.length} disclaimer patterns`
    });
  }

  // ========================================
  // CHECK 5: Generic response markers
  // ========================================
  const genericMarkers = [
    "here are some general",
    "here are the key",
