function parseNumberedList(text) {
  if (typeof text !== 'string') return null;

  // Match numbered items: "1. **Name** (optional sector)"
  const itemRegex = /(?:^|\n)\s*\d+\.\s+\*\*([^*]+)\*\*\s*(?:\(([^)]+)\))?/g;
  const positions = [];
  let match;

  while ((match = itemRegex.exec(text)) !== null) {
    positions.push({
      name: match[1].trim(),
      sector: match[2] ? match[2].trim() : null,
      start: match.index
    });
  }

  if (positions.length < 3) return null; // Need at least 3 items

  const results = [];
  for (let i = 0; i < positions.length; i++) {
    const start = positions[i].start;
    const end = i + 1 < positions.length ? positions[i + 1].start : text.length;
    const block = text.substring(start, end);

    const item = { _name: positions[i].name };
    if (positions[i].sector) item['Sector'] = positions[i].sector;

    // Parse "- **Key:** Value" pattern (bold key)
    const kvBold = /[-*]\s+\*\*([^*]+)\*\*[:\s]+(.+)/g;
    let kv;
    while ((kv = kvBold.exec(block)) !== null) {
      const key = kv[1].trim().replace(/:$/, '');
      let value = kv[2].trim();
      value = value.replace(/\[([^\]]*)\]\([^)]*\)/g, '$1');
      value = value.replace(/\s+$/, '');
      item[key] = value;
    }

    // Parse "- Key: Value" pattern (non-bold) if no bold keys found
    if (Object.keys(item).length <= 2) {
      const kvPlain = /[-*]\s+([A-Z][A-Za-z\s]+):\s+(.+)/g;
      let kv2;
      while ((kv2 = kvPlain.exec(block)) !== null) {
        const key = kv2[1].trim();
        let value = kv2[2].trim();
        value = value.replace(/\[([^\]]*)\]\([^)]*\)/g, '$1');
        value = value.replace(/\s+$/, '');
        item[key] = value;
      }
    }

    if (Object.keys(item).length > 1) {
      results.push(item);
    }
  }

  return results.length >= 3 ? results : null;
}

