  const founderCols = ['Founder', 'Founders', 'Founded By'];
  const roundCols = ['Round', 'Stage', 'Funding Stage', 'Funding Type'];
  const investorCols = ['Lead Investor', 'Lead Investors', 'Investors', 'Investor'];
  const dateCols = ['Date', 'Funding Date', 'Last Funding Date'];
  const amountCols = ['Amount', 'Amount Raised', 'Investment', 'Deal Size'];
  const revenueCols = ['Revenue', 'ARR', 'Annual Revenue'];

  // Always include these if available
  const mustHave = [];

  // Determine what type of table this is
  const isFunding = /\b(funding|funded|raised|series|investment|round)\b/.test(q);
  const isPortfolio = /\b(portfolio|invested|investments)\b/.test(q);
  const isRevenue = /\b(revenue|arr|sales)\b/.test(q);

  const selectedKeys = [];
  const keySet = allKeys;

  function pickFirst(candidates) {
    for (const c of candidates) {
      if (keySet.has(c)) {
        if (!selectedKeys.includes(c)) selectedKeys.push(c);
        return true;
      }
    }
    return false;
  }

  // Always try sector
  pickFirst(sectorCols);

  if (isFunding || isPortfolio) {
    pickFirst(fundingCols);
    pickFirst(roundCols);
    pickFirst(dateCols);
    pickFirst(investorCols);
    pickFirst(locationCols);
  } else if (isRevenue) {
    pickFirst(revenueCols);
    pickFirst(fundingCols);
    pickFirst(locationCols);
  } else {
    // General screening — funding + location
    pickFirst(fundingCols);
    pickFirst(locationCols);
    pickFirst(founderCols);
  }

  // Fill remaining columns (up to 5 total) with whatever is available
  const skip = new Set(['Description', 'Summary', 'Overview', 'About', 'Key Highlights']);
  for (const k of allKeys) {
    if (selectedKeys.length >= 5) break;
    if (!selectedKeys.includes(k) && !skip.has(k)) {
      selectedKeys.push(k);
    }
  }

  return selectedKeys.slice(0, 5);
}

function truncStr(s, max) {
  if (!s) return '-';
  s = String(s);
  return s.length > max ? s.substring(0, max - 1) + '...' : s;
}

function buildTableFromParsed(items, columns) {
  // Build header
  let header = '| # | Company |';
  let sep = '|---|---------|';
  for (const col of columns) {
    header += ` ${col} |`;
    sep += '---------|';
  }

  // Build rows
  const rows = items.map((item, i) => {
    let row = `| ${i + 1} | **${truncStr(item._name, 30)}** |`;
    for (const col of columns) {
      const val = item[col] || '-';
      row += ` ${truncStr(val, 35)} |`;
    }
    return row;
  });

  return [header, sep, ...rows].join('\n');
}

function extractIntroAndSummary(text, itemCount) {
  if (typeof text !== 'string') return { intro: '', summary: '' };

  const lines = text.split('\n');
  let intro = '';
  let summary = '';

  // First non-empty, non-list line is the intro
  for (const line of lines) {
    const t = line.trim();
    if (t && !/^\d+\.\s+\*\*/.test(t) && !/^[-*]\s+\*\*/.test(t) && !/^\|/.test(t)) {
      intro = t;
      break;
    }
  }

  // Last non-list paragraph is the summary
  const paragraphs = text.split(/\n\n+/);
  for (let i = paragraphs.length - 1; i >= 0; i--) {
    const p = paragraphs[i].trim();
    if (p && !/^\d+\.\s+\*\*/.test(p) && !/^[-*]\s+\*\*/.test(p) && !/^\|/.test(p) && p.length > 40) {
      // Avoid picking the intro as summary
      if (p !== intro) {
        summary = p;
      }
      break;
    }
  }

  return { intro, summary };
}

function formatAsTable(text, query) {
  // R3C-FIX-001: Preserve augmented sections during table formatting
  // Previously: discarded everything except intro + table + summary
  // Now: also preserves "**Additional...**", "**Research...**", "**Latest...**" sections

  // Already has a table? Skip
  if (/\|.*\|.*\|.*\|\n\|[-\s|]+\|\n/.test(text)) return null;

  const parsed = parseNumberedList(text);
  if (!parsed) return null;

  const columns = selectColumns(parsed, query);
  if (columns.length === 0) return null;

  const table = buildTableFromParsed(parsed, columns);
  const { intro, summary } = extractIntroAndSummary(text, parsed.length);

  // Extract augmented sections (from OPT-124 merge)
  const augmentedSections = [];
  const sectionRegex = /\n\n(\*\*(?:Additional|Research|Latest|Supplementary|Further)[^*]*\*\*[:\s]*\n[\s\S]*?)(?=\n\n\*\*|$)/gi;
  let sMatch;
  while ((sMatch = sectionRegex.exec(text)) !== null) {
    augmentedSections.push(sMatch[1].trim());
  }

  // Also capture *Sources: ...* footer
  const sourcesMatch = text.match(/\n\n(\*Sources:[^*]+\*)/);
  const sourcesFooter = sourcesMatch ? sourcesMatch[1] : '';

  const parts = [];
  if (intro) parts.push(intro);
  parts.push('');
  parts.push(table);
  if (summary) { parts.push(''); parts.push(summary); }
  // Append preserved augmented sections
  for (const section of augmentedSections) {
    parts.push('');
    parts.push(section);
  }
  if (sourcesFooter) {
    parts.push('');
    parts.push(sourcesFooter);
  }

  return parts.join('\n');
}

