function detectAggregationIntent(query) {
  const lowerQuery = query.toLowerCase();

  // Average/Mean
  if (/\b(average|mean|avg|typical)\b/.test(lowerQuery)) {
    return { type: 'average', metric: extractMetric(query) };
  }

  // Sum/Total
  if (/\b(total|sum|combined|aggregate)\b/.test(lowerQuery)) {
    return { type: 'sum', metric: extractMetric(query) };
  }

  // Median
  if (/\b(median|middle)\b/.test(lowerQuery)) {
    return { type: 'median', metric: extractMetric(query) };
  }

  // Maximum
  if (/\b(maximum|largest|highest|biggest|most)\b/.test(lowerQuery)) {
    return { type: 'max', metric: extractMetric(query) };
  }

  // Minimum
  if (/\b(minimum|smallest|lowest|least)\b/.test(lowerQuery)) {
    return { type: 'min', metric: extractMetric(query) };
  }

  // Count
  if (/\b(how many|count|number of)\b/.test(lowerQuery)) {
    return { type: 'count', metric: 'entities' };
  }

  return null; // No aggregation intent detected
}

function extractMetric(query) {
  if (/\b(funding|round size|investment|capital|raised)\b/i.test(query)) {
    return 'funding_amount';
  }
  if (/\b(valuation|worth)\b/i.test(query)) {
    return 'valuation';
  }
  if (/\b(employee|headcount|team size)\b/i.test(query)) {
    return 'employee_count';
  }
  if (/\b(revenue|ARR|MRR)\b/i.test(query)) {
    return 'revenue';
  }
  return 'value';
}

// ========================
// 2. EXTRACT NUMERIC VALUES
// ========================

function extractNumericValues(results, metric) {
  // Handle string results (non-Datalabs tools)
  if (typeof results === 'string') {
    return null; // No aggregation for text responses
  }

  // Handle array of results (Datalabs)
  if (!Array.isArray(results)) {
    results = [results];
  }

  const values = [];

  for (const result of results) {
    if (!result || typeof result !== 'object') continue;

    let value = null;

    switch (metric) {
      case 'funding_amount':
        value = result.amount || result.funding_amount || result.round_size || result.total_funding || result.last_funding_amount;
        break;
      case 'valuation':
        value = result.valuation || result.company_valuation;
        break;
      case 'employee_count':
        value = result.employees || result.headcount || result.team_size;
        break;
      case 'revenue':
        value = result.revenue || result.arr || result.mrr;
        break;
      default:
        // Try to find any numeric field
        value = findNumericField(result);
    }

    if (value !== null && value !== undefined) {
      const parsed = parseNumericValue(value);
      if (parsed !== null) {
        values.push({
          value: parsed,
          source: result.company_name || result.name || result.title || 'Unknown',
          raw: value,
          date: result.date || result.funding_date || result.last_funding_date
        });
      }
    }
  }

  if (values.length > 0) {
  }

  return values.length > 0 ? values : null;
}

function findNumericField(obj) {
  // Look for common numeric fields
  const numericFields = ['amount', 'value', 'size', 'total', 'count'];
  for (const field of numericFields) {
    if (obj[field] !== undefined) {
      return obj[field];
    }
  }
  return null;
}

function parseNumericValue(value) {
  if (typeof value === 'number') return value;

  const str = String(value).trim();

  // Handle millions: "$5.9M" → 5900000
  const millionMatch = str.match(/\$?(\d+\.?\d*)\s*M(?:illion)?/i);
  if (millionMatch) {
    return parseFloat(millionMatch[1]) * 1000000;
  }

  // Handle billions: "$1.2B" → 1200000000
  const billionMatch = str.match(/\$?(\d+\.?\d*)\s*B(?:illion)?/i);
  if (billionMatch) {
    return parseFloat(billionMatch[1]) * 1000000000;
  }

  // Handle thousands: "5000K" → 5000000
  const thousandMatch = str.match(/\$?(\d+\.?\d*)\s*K/i);
  if (thousandMatch) {
    return parseFloat(thousandMatch[1]) * 1000;
  }

  // Handle plain numbers with optional $ and commas
  const plainMatch = str.match(/\$?([\d,]+\.?\d*)/);
  if (plainMatch) {
    return parseFloat(plainMatch[1].replace(/,/g, ''));
  }

  return null;
}

// ========================
// 3. CALCULATE AGGREGATION
// ========================

function calculateAggregation(values, type) {
  if (!values || values.length === 0) {
    return { result: null, error: 'No numeric values found' };
  }

  const numericValues = values.map(v => v.value);

  switch (type) {
    case 'average':
      const sum = numericValues.reduce((a, b) => a + b, 0);
      return {
        result: sum / numericValues.length,
        count: numericValues.length,
        sum: sum
      };

    case 'sum':
      return {
        result: numericValues.reduce((a, b) => a + b, 0),
        count: numericValues.length
      };

    case 'median':
      const sorted = [...numericValues].sort((a, b) => a - b);
      const mid = Math.floor(sorted.length / 2);
      return {
        result: sorted.length % 2 === 0
          ? (sorted[mid - 1] + sorted[mid]) / 2
          : sorted[mid],
        count: numericValues.length
      };

    case 'min':
      return {
        result: Math.min(...numericValues),
        count: numericValues.length
      };

    case 'max':
      return {
        result: Math.max(...numericValues),
        count: numericValues.length
      };

    case 'count':
      return {
        result: numericValues.length,
        count: numericValues.length
      };

    default:
      return { result: null, error: 'Unknown aggregation type' };
  }
}

// ========================
// 4. GENERATE SAMPLE SIZE WARNING
// ========================

function generateSampleSizeWarning(sampleSize, aggregationType) {
  // Only warn for statistical aggregations
  if (!['average', 'median', 'sum'].includes(aggregationType)) {
    return null;
  }

  let reliability, icon, advice;

  if (sampleSize >= 20) {
    return null; // No warning needed
  } else if (sampleSize >= 10) {
    reliability = "Medium";
    icon = "🟡";
    advice = "This data provides a reasonable estimate but may not fully represent the market.";
  } else if (sampleSize >= 5) {
    reliability = "Low";
    icon = "🟠";
    advice = "This data is based on a limited sample. Treat as indicative rather than definitive.";
  } else {
    reliability = "Very Low";
    icon = "⚠️";
    advice = "This data is based on very few data points. Interpret as anecdotal rather than statistical.";
  }

  return {
    reliability,
    icon,
    message: `\n${icon} Data Reliability: ${reliability} (n=${sampleSize})\n${advice}`
  };
}

