function formatNumericValue(value, metric) {
  if (metric === 'funding_amount' || metric === 'valuation' || metric === 'revenue') {
    if (value >= 1000000000) {
      return `$${(value / 1000000000).toFixed(2)}B`;
    } else if (value >= 1000000) {
      return `$${(value / 1000000).toFixed(2)}M`;
    } else if (value >= 1000) {
      return `$${(value / 1000).toFixed(0)}K`;
    } else {
      return `$${value.toFixed(0)}`;
    }
  }
  return value.toLocaleString();
}

function metricToText(metric, plural = false) {
  const labels = {
    funding_amount: plural ? 'funding rounds' : 'funding amount',
    valuation: plural ? 'valuations' : 'valuation',
    employee_count: plural ? 'employee counts' : 'employee count',
    revenue: plural ? 'revenues' : 'revenue',
    value: plural ? 'values' : 'value',
    entities: plural ? 'entities' : 'entity'
  };
  return labels[metric] || metric;
}

function formatAggregationResponse(calculation, intent, values, warning, originalOutput) {
  const { type, metric } = intent;
  const { result, count } = calculation;

  if (result === null) {
    // No valid data, return original response
    return originalOutput;
  }

  const formattedResult = formatNumericValue(result, metric);

  let response = [];

  // 1. Main answer with calculation
  const aggregationText = type === 'count' ? 'number of' : type;
  response.push(`The ${aggregationText} ${metricToText(metric)} is approximately ${formattedResult}.`);

  // 2. Sample size warning if applicable
  if (warning) {
    response.push(warning.message);
  }

  // 3. Supporting data points (if <=10 items, show all)
  if (values.length > 0 && values.length <= 10) {
    response.push('');
    response.push(`${metricToText(metric, true).charAt(0).toUpperCase() + metricToText(metric, true).slice(1)} breakdown:`);
    values
      .sort((a, b) => b.value - a.value)
      .forEach((v, i) => {
        const dateStr = v.date ? ` (${v.date})` : '';
        response.push(`${i + 1}. ${v.source} - ${v.raw}${dateStr}`);
      });
  } else if (values.length > 10) {
    response.push('');
    response.push(`Based on ${values.length} data points. Top 5:`);
    values
      .sort((a, b) => b.value - a.value)
      .slice(0, 5)
      .forEach((v, i) => {
        response.push(`${i + 1}. ${v.source} - ${v.raw}`);
      });
  }

  // 4. Data completeness note for small samples
  if (count < 5) {
    response.push('');
    response.push(`Note: Only ${count} data point${count === 1 ? '' : 's'} available. More ${metricToText(metric, true)} may exist but are not in our current database.`);
  }

  return response.join('\n');
}

