      }
    });
  } else {
    for (const [key, value] of Object.entries(obj)) {
      // Convert snake_case to Title Case
      const label = key.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase());

      if (value === null || value === undefined) continue;

      if (Array.isArray(value)) {
        lines.push(indent + '**' + label + ':**');
        value.forEach((item, index) => {
          if (typeof item === 'object' && item !== null) {
            lines.push(indent + '  ' + (index + 1) + '. ' + jsonToMarkdown(item, level + 2).trim());
          } else {
            lines.push(indent + '  - ' + item);
          }
        });
      } else if (typeof value === 'object') {
        lines.push(indent + '**' + label + ':**');
        lines.push(jsonToMarkdown(value, level + 1));
      } else {
        lines.push(indent + '**' + label + ':** ' + value);
      }
    }
  }

  return lines.join('\n');
}

// Extract and convert output
function extractOutput(data) {
  if (!data) return '';

  let text = typeof data === 'string' ? data : JSON.stringify(data);

  // Remove markdown code blocks
  text = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

  // If it's JSON, parse and convert
  if (text.startsWith('{') || text.startsWith('[')) {
    try {
      let cleanJson = text.replace(/,\s*}/g, '}').replace(/,\s*]/g, ']');
      const parsed = JSON.parse(cleanJson);

      if (parsed && typeof parsed === 'object') {
        // Check for 'output' field first
        if (parsed.output && typeof parsed.output === 'string') {
          return parsed.output;
        }
        if (parsed.response && typeof parsed.response === 'string') {
          return parsed.response;
        }
        if (parsed.answer && typeof parsed.answer === 'string') {
          return parsed.answer;
        }
        if (parsed.text && typeof parsed.text === 'string') {
          return parsed.text;
        }

        // No text field found - convert the entire JSON to readable format
        return jsonToMarkdown(parsed);
      }
    } catch (e) {
      // JSON parse failed, return as-is
    }
  }

  return text;
}

// Extract output text
let rawOutput = extractOutput(input.output || input);

// Double-check for any remaining JSON
if (typeof rawOutput === 'string' && (rawOutput.trim().startsWith('{') || rawOutput.trim().startsWith('['))) {
  rawOutput = extractOutput(rawOutput);
}

if (isDatalabsQuery) {
  if (input._opt016_validation && input._opt016_validation.valid_count !== undefined) {
    sampleSize = input._opt016_validation.valid_count;
  } else if (raw_results.length > 0) {
    sampleSize = raw_results.length;
  } else if (rawOutput && typeof rawOutput === 'string') {
    const matches = rawOutput.match(/\d+\.\s*\*\*/g);
    if (matches) sampleSize = matches.length;
  }
}

const outputText = typeof rawOutput === 'string' ? rawOutput : '';
const isAggregation = /average|total|compare|trend|yoy/i.test(outputText);

let sampleWarning = null;
if (isDatalabsQuery && sampleSize > 0 && sampleSize < 20) {
  let reliability = sampleSize < 5 ? "Very Low" : (sampleSize < 10 ? "Low" : "Medium");
  let emoji = sampleSize < 5 ? "🔴" : (sampleSize < 10 ? "🟠" : "🟡");

  if (sampleSize < 5 || isAggregation) {
    sampleWarning = "\n\n---\n" + emoji + " **Data Reliability Notice**\nThis analysis is based on **" + sampleSize + " " + (sampleSize === 1 ? 'company' : 'companies') + "** from the database.\n- Statistical Confidence: **" + reliability + "**\n- Consider this data as directional rather than definitive.\n---";
  }
}

let finalOutput = rawOutput;

if (hasToolError) {
  finalOutput = "Unable to find the answer at this time. We will take this as feedback and improve our system.\n\nPlease try again later or rephrase your question.";
} else if (isHallucination) {
  finalOutput = "⚠️ **Data Verification Notice**\n\nThis response is based on general AI knowledge, **not verified Inc42 data**. The system attempted to use Inc42 tools but they did not return sufficient data.\n\n**Please Note:**\n- This information may not be accurate for the Indian startup ecosystem\n- No sources from Inc42 database were used\n- Consider trying a different query or rephrasing\n\n---\n\n" + finalOutput;
}

if (sampleWarning && typeof finalOutput === 'string' && !hasToolError) {
  finalOutput = finalOutput + sampleWarning;
}

const response = {
  output: finalOutput,
  sources: sources,
  fallback_used: input.fallback_used || false,
  fallback_strategy: input.fallback_strategy || null,
  raw_results: raw_results,
  validation_criteria: input.validation_criteria || null,
  _opt018_sample_size: sampleSize,
  _opt018_warning_shown: !!sampleWarning,
  _opt018_is_datalabs: isDatalabsQuery,
  _opt038_tool_error: hasToolError,
  _opt038_hallucination: isHallucination,
  _opt038_status: hasToolError ? "tool_error" : (isHallucination ? "hallucination" : "success"),
  _opt038_timestamp: new Date().toISOString()
};


// OPT-046: Rich Response Formatting
// Detect query type and apply appropriate formatting
const queryLower = (input.chatInput || '').toLowerCase();

function formatFundingTable(text) {
  // Look for funding round data and convert to markdown table
  const roundPattern = /(?:Series [A-F]|Seed|Pre-Seed|Angel|IPO|Pre-IPO)\s*(?:round)?\s*[-–:]\s*\$[\d.,]+\s*(?:million|billion|M|B|Mn|Bn|Cr)?/gi;
  const rounds = text.match(roundPattern);
  if (rounds && rounds.length >= 2) {
    let table = '\n\n| Round | Amount | Details |\n|-------|--------|--------|\n';
    rounds.forEach(round => {
      const parts = round.split(/[-–:]/);
      if (parts.length >= 2) {
        table += `| ${parts[0].trim()} | ${parts.slice(1).join(':').trim()} | |\n`;
      }
    });
    // Append table after the text if not already formatted as table
    if (!text.includes('| Round |')) {
      text = text + table;
    }
  }
  return text;
}

function formatComparisonTable(text) {
  // For "vs" or "compare" queries, try to structure as side-by-side
  const entities = queryLower.match(/(\w+)\s+(?:vs|versus|compared?\s+(?:to|with))\s+(\w+)/i);
  if (entities && entities.length >= 3) {
    const [, entity1, entity2] = entities;
    // Only add comparison header if response mentions both entities
    if (text.toLowerCase().includes(entity1) && text.toLowerCase().includes(entity2)) {
      if (!text.includes('| Metric |') && !text.includes('| Feature |')) {
        // Add a comparison prompt at the start
        text = `**Comparing ${entity1.charAt(0).toUpperCase() + entity1.slice(1)} vs ${entity2.charAt(0).toUpperCase() + entity2.slice(1)}**\n\n` + text;
      }
    }
  }
  return text;
}

function formatTimeline(text) {
  // For timeline/history queries, ensure chronological bullet points
  const yearMentions = text.match(/\b(20\d{2})\b/g);
  if (yearMentions && yearMentions.length >= 3) {
    // Response already has multiple years — ensure they're in order
    // This is a light touch — just add a timeline header if none exists
    if (!text.includes('## Timeline') && !text.includes('## History') && !text.includes('## Journey')) {
      const hasChronological = /20\d{2}.*20\d{2}.*20\d{2}/s.test(text);
      if (hasChronological) {
        text = text.replace(/^(#{1,3}\s)/, '$1📅 ');
      }
    }
  }
  return text;
}

// Apply formatting based on query type
if (/\b(funding|raised|series|round|investment)\b/i.test(queryLower)) {
  response.output = formatFundingTable(response.output);
} else if (/\b(vs|versus|compare|comparison|difference|between)\b/i.test(queryLower)) {
  response.output = formatComparisonTable(response.output);
} else if (/\b(timeline|history|journey|evolution|story|path)\b/i.test(queryLower)) {
  response.output = formatTimeline(response.output);
}

// OPT-153: Cost Estimation
const tokenEstimate = (input.output || '').length / 4;
const inputTokens = (input.chatInput || '').length / 4;
const costPerOutputToken = 0.000015; // GPT-4o output
const costPerInputToken = 0.000005; // GPT-4o input
const baseCost = (tokenEstimate * costPerOutputToken) + (inputTokens * costPerInputToken);
const toolCalls = (input.sources || []).length;
const toolCost = toolCalls * 0.002; // estimated per-tool cost
const augmentationCost = input._augmentation_triggered ? 0.005 : 0; // Perplexity Sonar
response._cost_estimate = Math.round((baseCost + toolCost + augmentationCost) * 10000) / 10000;
return { json: response };

// OPT-004: Write Cache
// Stores response in in-memory cache

const input = $input.first().json;

// Get original query from Check Cache node (which has the webhook data)
let cacheKey = null;
try {
  const checkCacheData = $("OPT-004: Check Cache").first().json;
  cacheKey = checkCacheData._cache_key;
    // OPT-155c: Override cache key with resolved query for session isolation
    const _resolvedQ = ($input.first().json._resolved_query || '').trim();
    if (_resolvedQ) {
      cacheKey = _resolvedQ.toLowerCase()
        .replace(/[^\w\s]/g, '')
        .replace(/\s+/g, ' ')
        .split(' ')
        .filter(w => w.length > 2)
        .sort()
        .join('_')
        .substring(0, 100);
    }

} catch (e) {
  // Fallback: Generate key from webhook body
  try {
    const webhookData = $("Webhook").first().json;
    const query = webhookData.body?.chatInput || webhookData.chatInput || "";
    cacheKey = query
      .toLowerCase()
      .trim()
      .replace(/[^\w\s]/g, "")
      .replace(/\s+/g, " ")
      .split(" ")
      .filter(w => w.length > 2)
      .sort()
      .join("_")
      .substring(0, 100);
  } catch (e2) {
    cacheKey = null;
  }
}

// Only cache if we have a key and a valid response
if (!cacheKey || !input.output) {
  return { json: input };
}

// Determine TTL based on response content/sources
const determineTTL = (response) => {
  const sources = response.sources || [];
  // Safe conversion of output to string for pattern matching
  let output = "";
  if (typeof response.output === "string") {
    output = response.output.toLowerCase();
  } else if (response.output != null) {
    output = JSON.stringify(response.output).toLowerCase();
  }

  // News/Updates queries - 15 minutes
  if (sources.includes("Inc42 Updates") ||
      output.includes("recent") ||
      output.includes("latest") ||
      output.includes("news")) {
    return 15 * 60 * 1000;
  }

  // Funding queries - 2 hours
  if (sources.includes("Datalabs") &&
      (output.includes("funding") ||
       output.includes("series") ||
       output.includes("raised"))) {
    return 2 * 60 * 60 * 1000;
  }

  // Company/founder queries - 12 hours
  if (output.includes("founded") ||
      output.includes("founder") ||
      output.includes("ceo")) {
    return 12 * 60 * 60 * 1000;
  }

  // Default - 1 hour
  return 2 * 60 * 60 * 1000;
};

const ttl = determineTTL(input);
const now = Date.now();

// Get static data
const staticData = $getWorkflowStaticData("global");
staticData.cache = staticData.cache || {};

// Clean expired entries (max 100 entries)
const entries = Object.entries(staticData.cache);
if (entries.length > 500) {
  const validEntries = entries
    .filter(([k, v]) => v.expires > now)
    .sort((a, b) => b[1].timestamp - a[1].timestamp)
    .slice(0, 400);
  staticData.cache = Object.fromEntries(validEntries);
}

// Store new entry
staticData.cache[cacheKey] = {
  response: {
    output: input.output,
    sources: input.sources,
    fallback_used: input.fallback_used,
    raw_results: input.raw_results
  },
  timestamp: now,
  expires: now + ttl,
  ttl_minutes: Math.floor(ttl / 60000)
};


// C-5: Redis cache write (Sprint 2) — writes alongside staticData above
try {
  const Redis = require('ioredis');
  const redisClient = new Redis({
    host: '127.0.0.1', port: 6379,
    password: $('env').first().json.REDIS_PASSWORD,
    connectTimeout: 1000,
    maxRetriesPerRequest: 0,
    lazyConnect: true
  });
  await redisClient.connect();
  const ttlSeconds = Math.max(60, Math.floor(ttl / 1000));
  await redisClient.set(
    'ask:cache:' + cacheKey,
    JSON.stringify({
      response: { output: input.output, sources: input.sources, fallback_used: input.fallback_used, fallback_strategy: input.fallback_strategy || null },
      timestamp: now,
      query: input.chatInput || ''
    }),
    'EX', ttlSeconds
  );
  await redisClient.quit();
} catch (e) {
  // Redis not available — staticData write above is the fallback
}

// Return response with cache metadata
return {
  json: {
    ...input,
    _cached_at: new Date(now).toISOString(),
    _cache_ttl_minutes: Math.floor(ttl / 60000),
    _cache_key: cacheKey
  }
};

// OPT-083: Honest Response Formatter + OPT-103: No Data Available
// Intercepts responses that only have unverified/general knowledge sources
// or empty tool results, and reformats with honesty disclaimer.
// Also strips internal error language from partial-success responses.

const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const output = data.output || '';
  const sources = data.sources || [];
  const originalQuery = data.chatInput || data._original_query ||
    data._opt017_original_query || 'this topic';

  // Check if ALL sources are unverified/general knowledge
  const sourceStrings = sources.map(s =>
    typeof s === 'string' ? s : (s.title || s.source || JSON.stringify(s))
  );
  const hasOnlyUnverifiedSources = sourceStrings.length > 0 &&
    sourceStrings.every(s =>
      s.toLowerCase().includes('ai general knowledge') ||
      s.toLowerCase().includes('unverified') ||
      s.toLowerCase().includes('general knowledge')
    );

  // OPT-103: Detect empty tool results / no data available
  const noDataPhrases = [
    'could not find', 'couldn\'t find', 'no results',
    'no data available', 'no information available',
    'no relevant data', 'no specific data',
    'unable to find', 'i don\'t have specific data',
    'i don\'t have information'
  ];
  const outputLower = output.toLowerCase();
  const hasNoDataPhrase = noDataPhrases.some(p => outputLower.includes(p));
  const hasEmptySources = sourceStrings.length === 0;
  const isExplicitFailure = data.success === false;
  const isVeryShort = output.length > 0 && output.length < 100;
  const isNoData = (hasEmptySources && (hasNoDataPhrase || isExplicitFailure || isVeryShort)) ||
    (hasNoDataPhrase && isVeryShort);

  // Detect internal error language in responses that have useful content
  // These patterns leak implementation details to users
  const internalErrorPatterns = [
    /the\s+(?:datalabs|inc42\s+context|inc42\s+updates?)\s+tool\s+returned\s+(?:an?\s+)?(?:empty_output|tool_error|error|no\s+results?)\s*(?:error)?/gi,
    /\bempty_output\s+error\b/gi,
    /\btool_error\b/gi,
    /\btool\s+returned\s+(?:an?\s+)?error\b/gi,
    /\bthe\s+system\s+attempted\s+to\s+use\s+(?:inc42|datalabs)\s+tools?\s+but\s+received\s+insufficient\s+data\b/gi,
    /\bsearching\s+for\s+["'][^"']+["']\s*,\s*["'][^"']+["']\s*(?:,\s*and\s*["'][^"']+["'])?\)/gi,
  ];
  const hasInternalErrorLanguage = internalErrorPatterns.some(p => p.test(output));

  if (isNoData) {
    // OPT-103: Empty tool results — honest "no data" response
    const formattedOutput =
      `I searched our Inc42 and Datalabs databases but couldn't find specific data for "${originalQuery}".\n\n` +
      `**What I searched:**\n` +
      `- Inc42 Context (company profiles, founder stories, industry analysis)\n` +
      `- Inc42 Updates (recent news, last 90 days)\n` +
      `- Datalabs (funding rounds, investor data, company directory)\n\n` +
      `**Suggestions:**\n` +
      `- Try rephrasing with a specific company or investor name\n` +
      `- Use broader terms (e.g., "FinTech funding" instead of a specific round)\n` +
      `- Check inc42.com for in-depth articles on this topic\n\n` +
      `*This is an honest acknowledgment that our databases don't have this specific information.*`;

    results.push({
      json: {
        ...data,
        output: formattedOutput,
        sources: ['System — No Data Available'],
        _opt083_reformatted: true,
        _opt103_no_data: true,
        _opt103_reason: isExplicitFailure ? 'explicit_failure' :
          hasEmptySources ? 'empty_sources' : 'no_data_phrase'
      }
    });
  } else if (hasInternalErrorLanguage && output.length > 200) {
    // NEW: Response has useful content but starts with or contains internal error language
    // Strip the error paragraphs and keep the useful parts
    let cleanedOutput = output;

    // Remove opening error paragraph(s) that describe tool failures
    // Pattern: "Could not find... The Datalabs tool returned an empty_output error... [internal details]"
    cleanedOutput = cleanedOutput.replace(
      /^(?:Could\s+not\s+find\s+relevant\s+information\.?\s*)?(?:The\s+(?:Datalabs|Inc42\s+\w+)\s+tool\s+returned\s+(?:an?\s+)?(?:empty_output|tool_error|error)\s+(?:error\s+)?(?:for\s+(?:multiple\s+)?(?:queries?|searches?)\s+(?:aimed\s+at|targeting|about|for)\s+[^.]+\.\s*(?:\([^)]+\)\s*)?)+)+/gi,
      ''
    );

    // Remove any remaining sentences about tool errors
    cleanedOutput = cleanedOutput.replace(
      /(?:^|\n)[^\n]*(?:empty_output|tool_error|tool\s+returned\s+(?:an?\s+)?error|system\s+attempted\s+to\s+use\s+(?:Inc42|Datalabs)\s+tools?\s+but)[^\n]*(?:\n|$)/gi,
      '\n'
    );

    // Remove "Without any tool results..." sentences
    cleanedOutput = cleanedOutput.replace(
      /Without\s+any\s+tool\s+results\s+[^.]+\.\s*/gi,
      ''
    );

    // Clean up leading whitespace/newlines
    cleanedOutput = cleanedOutput.replace(/^\s*\n+/, '').trim();

    // If after cleaning there's still useful content, add a gentle note
    if (cleanedOutput.length > 100) {
      // Add a note if the response mentions "Supplementary Context" or "Web Research"
      cleanedOutput = cleanedOutput.replace(
        /\*\*Supplementary\s+Context\s*\(Web\s+Research\):\*\*/gi,
        '**Based on available data:**'
      );

      // Add a closing note about data limitations
      if (!cleanedOutput.includes('specific data') && !cleanedOutput.includes('comprehensive analysis')) {
        cleanedOutput += '\n\n---\n*Note: Our structured database has limited coverage for this specific query. The above is based on available data sources.*';
      }

      results.push({
        json: {
          ...data,
          output: cleanedOutput,
          _opt083_reformatted: true,
          _opt083_error_stripped: true,
          _opt083_original_length: output.length,
          _opt083_cleaned_length: cleanedOutput.length
        }
      });
    } else {
      // After stripping, not enough useful content — fall through to no-data handler
      const formattedOutput =
        `Our databases have limited coverage for "${originalQuery}". Here's what we found:\n\n` +
        cleanedOutput +
        `\n\n---\n*For more comprehensive data, try asking about specific companies or investors by name.*`;

      results.push({
        json: {
          ...data,
          output: formattedOutput,
          _opt083_reformatted: true,
          _opt083_error_stripped: true,
          _opt083_limited_data: true
        }
      });
    }
  } else if (hasOnlyUnverifiedSources && output) {
    // OPT-083: Unverified sources — honesty disclaimer
    const formattedOutput =
      `I don't have specific Inc42 or Datalabs data on this topic. ` +
      `Here's what I can share based on general knowledge:\n\n` +
      output +
      `\n\n---\n` +
      `*Note: This response is based on general knowledge, not verified Inc42/Datalabs data. ` +
      `For verified startup data, try asking about specific companies, funding rounds, or investors.*`;

    results.push({
      json: {
        ...data,
        output: formattedOutput,
        sources: ['AI General Knowledge (Unverified — reformatted by OPT-083)'],
        _opt083_reformatted: true,
        _opt083_original_sources: sourceStrings
      }
    });
  } else if (data._opt029_bypass_type === 'irrelevant_sources' && output) {
    // OPT-098: Sources exist but are about wrong topic
    const formattedOutput =
      `The sources I found may not be directly relevant to your specific query about "${originalQuery}". ` +
      `Here's what was available:\n\n` +
      output +
      `\n\n---\n` +
      `*Note: The available sources may not precisely match your query. ` +
      `Try rephrasing with a specific company name or topic for more targeted results.*`;

    results.push({
      json: {
        ...data,
        output: formattedOutput,
        _opt083_reformatted: true,
        _opt083_reformat_reason: 'irrelevant_sources'
      }
    });
  } else {
    // Pass through unchanged — has real data sources
    results.push(item);
  }
}

return results;

// OPT-094: Strip internal metadata before webhook response
// V3.5 (Sprint 1): Added S-2 Datalabs URLs, S-3 Inc42 URL extraction
// V3.6 (Sprint 2): Added S-4 source ordering, S-5 normalization
// EDGE-02: Source URL validation — remove hallucinated/untrusted URLs
const input = $input.first().json;

// EDGE-02: Trusted domain list
const TRUSTED_DOMAINS = [
  'inc42.com', 'crunchbase.com', 'tracxn.com', 'linkedin.com',
  'wikipedia.org', 'economictimes.com', 'livemint.com',
  'moneycontrol.com', 'reuters.com', 'bloomberg.com',
  'techcrunch.com', 'yourstory.com', 'entrackr.com',
  'forbes.com', 'business-standard.com', 'ndtv.com',
  'cnbctv18.com', 'vccircle.com', 'dealstreetasia.com',
  'rbi.org.in', 'sebi.gov.in', 'mca.gov.in'
];

function validateSource(source) {
  if (typeof source === 'string') return source;
  if (typeof source !== 'object' || source === null) return source;

  const url = source.uri || source.url || '';
  if (!url || !url.startsWith('http')) return source;

  try {
    const hostname = new URL(url).hostname.replace(/^www\./, '');
    const isTrusted = TRUSTED_DOMAINS.some(d => hostname === d || hostname.endsWith('.' + d));
    if (isTrusted) return source;
    const cleaned = { title: source.title || 'Source' };
    if (source.source) cleaned.source = source.source;
    return cleaned;
  } catch (e) {
    const cleaned = { title: source.title || 'Source' };
    if (source.source) cleaned.source = source.source;
    return cleaned;
  }
}

const rawSources = input.sources || [];
const validatedSources = rawSources.map(validateSource);

const clean = {
  output: input.output || '',
  sources: validatedSources,
  fallback_used: input.fallback_used || false,
  fallback_strategy: input.fallback_strategy || null
};

if (input.chatInput) clean.chatInput = input.chatInput;
if (input.suggestions) clean.suggestions = input.suggestions;

// SEC-08: Timeout notice
if (input._timeout_triggered) {
  clean.output += '\n\n---\n*Note: This response may be incomplete due to processing time limits.*';
  clean._timeout = true;
}

// EDGE-01: Data coverage notice for critical failures
if (input._edge01_health === 'critical' && !input._opt122_needs_augmentation) {
  clean.output = "I'm experiencing temporary issues accessing some data sources. " +
    "Here's what I could find:\n\n" + (clean.output || "Please try again in a moment.");
  clean._data_coverage = 'limited';
}


// EDGE-07: Response length cap
const MAX_RESPONSE_LENGTH = 5000;
if (clean.output.length > MAX_RESPONSE_LENGTH) {
  const truncated = clean.output.substring(0, MAX_RESPONSE_LENGTH);
  const lastSection = truncated.lastIndexOf('\n## ');
  const lastParagraph = truncated.lastIndexOf('\n\n');
  const cutPoint = lastSection > MAX_RESPONSE_LENGTH * 0.6
    ? lastSection
    : (lastParagraph > MAX_RESPONSE_LENGTH * 0.6 ? lastParagraph : MAX_RESPONSE_LENGTH);
  clean.output = truncated.substring(0, cutPoint) +
    '\n\n---\n*Response truncated for readability. Ask a more specific question for detailed information.*';
  clean._truncated = true;
  clean._original_length = clean.output.length;
}


// EDGE-10: Cache age indicator
if (input._cache_status === 'hit') {
  const ageSeconds = input._cache_age_seconds || 0;
  let ageLabel;
  if (ageSeconds < 60) ageLabel = 'just now';
  else if (ageSeconds < 3600) ageLabel = Math.floor(ageSeconds / 60) + ' minutes ago';
  else ageLabel = Math.floor(ageSeconds / 3600) + ' hours ago';
  clean.cache_info = { from_cache: true, cached_at: ageLabel, age_seconds: ageSeconds };
}

// D4: Cache monitoring — always include _cache_hit for analytics
if (input._cache_status === "hit") {
  clean._cache_hit = true;
} else {
  clean._cache_hit = false;
  clean.cache_info = { from_cache: false };
}


// S-2b: Add Datalabs profile links — dynamic slugs from pipeline + hardcoded fallback (Sprint 2)
