  const existingUris = new Set(clean.sources.filter(s => typeof s === 'object' && s.uri).map(s => s.uri));
  const outputLowerForSlugs = outputTextForUrls.toLowerCase();
  for (const [name, slug] of Object.entries(mergedSlugs)) {
    const uri = DATALABS_BASE + '/company/' + slug;
    if (outputLowerForSlugs.includes(name) && !addedSlugs.has(slug) && !existingUris.has(uri)) {
      addedSlugs.add(slug);
      clean.sources.push({
        title: name.split(' ').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ') + ' \u2014 Datalabs Profile',
        uri: uri,
