  }
}


// S-3: Extract Inc42 article URLs from response text (Sprint 1)
const INC42_URL_PATTERN = /https?:\/\/(?:www\.)?inc42\.com\/[^\s"'<>)\]]+/gi;
const inc42Urls = (clean.output || '').match(INC42_URL_PATTERN) || [];

const seenUrls = new Set(clean.sources.filter(s => typeof s === 'object' && s.uri).map(s => s.uri));
for (const url of inc42Urls) {
  const cleanUrl = url.replace(/[.,;:!?]+$/, '');
  if (!seenUrls.has(cleanUrl) && cleanUrl.length > 25) {
    seenUrls.add(cleanUrl);
    const pathParts = cleanUrl.replace(/https?:\/\/(?:www\.)?inc42\.com\//, '').split('/').filter(Boolean);
    const lastPart = pathParts[pathParts.length - 1] || 'article';
    const title = lastPart.replace(/-/g, ' ').replace(/^\w/, c => c.toUpperCase());
    clean.sources.push({
      title: 'Inc42: ' + title,
      uri: cleanUrl,
      type: 'inc42_article'
    });
  }
}



// S-5: Normalize all sources to {title, uri, type} objects + dedup (Sprint 2)
clean.sources = clean.sources.map(source => {
  if (typeof source === 'string') {
    const lower = source.toLowerCase();
    let type = 'proprietary';
    if (lower.includes('[web]') || lower.includes('perplexity')) type = 'web';
    if (lower.includes('general knowledge')) type = 'ai_general';
    if (lower.includes('error') || lower.includes('no data')) type = 'system';
    return { title: source, uri: '', type };
  }
  if (typeof source === 'object' && source !== null) {
    const uri = source.uri || source.url || '';
    return {
      title: source.title || source.source || 'Unknown Source',
      uri: uri,
      type: source.type || (
        uri.includes('inc42.com/company/') ? 'datalabs_profile' :
        uri.includes('inc42.com') ? 'inc42_article' :
        (source.title || '').includes('[Web]') ? 'web' : 'proprietary'
      )
    };
  }
  return { title: String(source), uri: '', type: 'unknown' };
});

// Dedup by URI (if present) or title
const seenSourceKeys = new Set();
clean.sources = clean.sources.filter(s => {
  const key = s.uri || s.title;
  if (seenSourceKeys.has(key)) return false;
  seenSourceKeys.add(key);
  return true;
});

// S-4: Source priority ordering — proprietary first, web last (Sprint 2)
function sourceWeight(source) {
  if (typeof source === 'object' && source.type === 'datalabs_profile') return 0;
  if (typeof source === 'object' && source.type === 'inc42_article') return 1;
  const text = typeof source === 'string' ? source : (source.title || '');
  const lower = text.toLowerCase();
  if (lower.includes('inc42')) return 2;
  if (lower.includes('datalabs') || lower.includes('scoutdb')) return 3;
  if (lower.includes('[web]') || lower.includes('perplexity')) return 5;
  return 4;
}
clean.sources.sort((a, b) => sourceWeight(a) - sourceWeight(b));

// === NDJSON Generation ===
const ndjsonLines = [];
ndjsonLines.push(JSON.stringify({type: 'status', status: 'complete', query: clean.chatInput || ''}));

const text = clean.output || '';
const sections = text.split(/\n(?=##\s)/).filter(s => s.trim());
if (sections.length > 1) {
  sections.forEach((section, idx) => {
    ndjsonLines.push(JSON.stringify({type: 'result_chunk', index: idx, content: section.trim()}));
  });
} else {
  const paragraphs = text.split(/\n\n+/).filter(p => p.trim());
  if (paragraphs.length > 1) {
    paragraphs.forEach((para, idx) => {
      ndjsonLines.push(JSON.stringify({type: 'result_chunk', index: idx, content: para.trim()}));
    });
  } else {
    ndjsonLines.push(JSON.stringify({type: 'result_chunk', index: 0, content: text.trim()}));
  }
}

ndjsonLines.push(JSON.stringify({
