const chatInput = $json.chatInput || $json.body?.chatInput || $json.query?.chatInput || '';
const query = chatInput.toLowerCase().trim();
const queryLength = chatInput.trim().length;

// ========================
// EXTENDED SIMPLE PATTERNS (OPT-156)
// ========================

const simplePatterns = [
  // Founder queries
  /^who\s+(founded|started|created|co-?founded|is\s+the\s+(?:founder|ceo|cto|coo))/i,

