  /^(?:top|best|biggest|largest|leading|fastest)\s+\d*\s*(?:fintech|edtech|healthtech|saas|d2c|ai|ev|agritech|deeptech|logistics|gaming|crypto|web3|biotech|proptech|insurtech|hrtech|foodtech|cleantech|spacetech|legaltech|mediatech|traveltech|autotech|wealthtech|neobank|cybersecurity)\s+(?:startups?|companies?|brands?|firms?|players?|platforms?)$/i,

  // Implicit metric: "[Company] + [year]" pattern (e.g., "Razorpay 2025")
  /^[A-Z][a-zA-Z0-9\s]{1,25}\s+(?:20\d{2}|last\s+year|this\s+year)$/i,

  // ========================
  // BLOCK1-PIPELINE-001: Expanded Fast-Path Patterns (P2)
  // Goal: 80%+ of queries bypass the non-deterministic decomposer LLM
  // ========================

  // Investor queries — single Datalabs investor search
  /^(?:who|which)\s+(?:vcs?|investors?|venture\s+capital|angels?)\s+(?:invest|fund|back|are)/i,
  /\b(?:invested|investing|investments?)\s+(?:in|by)\s+/i,
  /\b(?:portfolio|portfolio\s+companies?)\s+(?:of|for)\s+/i,
  /\b(?:sequoia|peak\s+xv|accel|matrix|z47|tiger\s+global|softbank|blume|kalaari|nexus|elevation)\b/i,

  // Sector queries — "top N in sector" or "state of sector"
  /^(?:top|best|biggest|largest|leading|fastest)\s+\d*\s*(?:\w+\s+)*?(?:in|from)\s+(?:india|indian)/i,
  /\b(?:state\s+of|ecosystem|landscape|overview\s+of)\s+(?:\w+\s+)*?(?:in\s+india|indian)/i,

  // Salary / compensation queries — Perplexity augmentation handles these
  /\b(?:salary|salaries|compensation|pay\s+scale|earning|ctc|package|remuneration)\b.*\b(?:engineer|developer|designer|manager|executive|intern|analyst)/i,

  // Year comparison queries — force simple, agent combines years in one search
  /\b20\d{2}\s*(?:vs\.?|versus|compared?\s+to)\s*20\d{2}\b/i,
  /\b(?:compared?\s+to|decline|growth\s+trend|more|fewer|less)\b.*\b(?:in|during)\s+20\d{2}\b.*\b(?:vs|than|compared|from)\b/i,
  /\b(?:decline|declining|growth|growing|increasing|decreasing)\b.*\b20\d{2}\b.*\b(?:compared|vs|than|from)\b.*\b20\d{2}\b/i,

  // Investor portfolio queries (single investor)
  /^(?:what|which)\s+(?:startups?|companies?)\s+(?:has|have|did)\s+\w+(?:\s+\w+)?\s+(?:invested|funded|backed)/i,

  // ========================
  // L2-SPEED: Additional Fast-Path Patterns (Phase 1 Speed Optimization)
  // Goal: +5-8% fast-path coverage for common simple queries
  // ========================

  // Company competitors — single Datalabs sector search
  /^(?:who\s+are|what\s+are|list)\s+(.+?)(?:'s)?\s+(?:competitors?|rivals?|alternatives?)/i,

  // Company team/leadership — single Inc42 Context search
  /^(?:who\s+(?:is|are)\s+(?:the|in)\s+)?(.+?)(?:'s)?\s+(?:team|leadership|management|board|co-?founders?|executives?)/i,

  // "How many employees" — single Datalabs lookup
  /^how\s+many\s+employees?\s+(?:does|do|has|have|at|in)\s+/i,

  // Company acquisition/exit — single Datalabs + Inc42 Context
  /^(?:has|did|was)\s+(.+?)\s+(?:been\s+)?(?:acquired|bought|merged|gone\s+public|ipo)/i,
];

// ========================
// LENGTH + COMPLEXITY CHECK (OPT-156)
// ========================

const isShortQuery = queryLength < 60;
const hasConjunction = /\b(and|vs|versus|compare|between|or)\b/i.test(query);
const hasMultipleQuestions = (query.match(/\?/g) || []).length > 1;
const hasComplexModifiers = /\b(how\s+did|why\s+did|what\s+drove|strategy|scaling|growth\s+story|business\s+model)\b/i.test(query);

const patternMatch = simplePatterns.some(p => p.test(chatInput.trim()));
const isSimpleByLength = isShortQuery && !hasConjunction && !hasMultipleQuestions && !hasComplexModifiers;

// A query is simple if it matches a pattern OR is short + simple structure
const isSimple = patternMatch || (isSimpleByLength && /^(who|what|when|where|how much|tell me about|top|latest|last|[A-Z])\b/i.test(query));

// ========================
// TOOL HINT GENERATION (OPT-156)
// ========================

let toolHint = 'all';
let fastPathResult = null;

if (isSimple) {
  // Determine which single tool to use
  if (/founder|ceo|cto|started|created|who\s+is|tell\s+me\s+about/i.test(query)) {
    toolHint = 'inc42_context';
  } else if (/funding|raised|valuation|revenue|series|round|invested|investor/i.test(query)) {
    toolHint = 'datalabs';
  } else if (/latest|recent|news|update|happened/i.test(query)) {
    toolHint = 'inc42_updates';
  } else if (/top|best|biggest|leading/i.test(query)) {
    toolHint = 'datalabs';
  } else {
    toolHint = 'inc42_context';
  }


  // BLOCK1-PIPELINE-001: Tool hints for expanded patterns
  if (/\b(salary|salaries|compensation|pay|ctc|package|remuneration)\b/i.test(query)) {
    toolHint = 'inc42_context';  // Salary data comes via Perplexity augmentation
  } else if (/\b(sequoia|peak\s*xv|accel|matrix|z47|tiger|softbank|blume|kalaari|nexus|elevation)\b/i.test(query)) {
    toolHint = 'datalabs';  // Investor data from ES
  }

  // L2-SPEED: Tool hints for additional fast-path patterns
  if (/\b(competitors?|rivals?|alternatives?)\b/i.test(query)) {
    toolHint = 'datalabs';  // Competitor data from sector search
  } else if (/\b(team|leadership|management|board|executives?)\b/i.test(query)) {
    toolHint = 'inc42_context';  // People data
  } else if (/how\s+many\s+employee/i.test(query)) {
    toolHint = 'datalabs';  // Employee count from ES
  } else if (/\b(acquired|bought|merged|ipo|gone\s+public)\b/i.test(query)) {
    toolHint = 'datalabs';  // Acquisition/exit data
  }

  fastPathResult = {
    isSimple: true,
    toolHint: toolHint,
    skipDecomposition: true,
    query: chatInput.trim(),
    _fast_path: true,
    _fast_path_reason: patternMatch ? 'pattern_match' : 'short_simple'
  };
}

// Pass through all input data
const result = {
  ...$json,
  isSimple: isSimple,
  _fast_path_evaluated: true,
  _query_length: queryLength,
  _pattern_match: patternMatch,
  _simple_by_length: isSimpleByLength
};

if (fastPathResult) {
  Object.assign(result, fastPathResult);
}

return [{ json: result }];

// OPT-122: Source Sufficiency Check
