// ========================================
// BLOCK2-DATA-001 / D3: HONEST DECLINE FOR KNOWN DATA GAPS
// ========================================
// For queries where our databases structurally lack data (salaries, tech stacks,
// hiring patterns), we flag _honest_decline so the response formatter can prefix
// with a transparency disclaimer instead of producing misleading padded content.

const salaryPattern = /\b(salary|salaries|compensation|pay scale|earning|ctc|package|remuneration|pay band|pay range|stipend)\b/i;
const techStackPattern = /\b(tech stack|technology stack|programming language|framework|tools? used|built with|infrastructure|devops|technical architecture)\b/i;
const hiringPattern = /\b(hiring pattern|recruitment|job opening|open position|headcount|attrition|employee turnover)\b/i;

const isKnownDataGap = salaryPattern.test(originalQuery) || techStackPattern.test(originalQuery) || hiringPattern.test(originalQuery);

// Check if Datalabs actually returned relevant data (not just company metadata)
const hasRelevantDatalabsData = sources.some(s => {
  const t = getSourceText(s);
  return (t.includes('datalabs') || t.includes('inc42')) && !t.includes('general knowledge');
}) && output.length > 800;

if (isKnownDataGap && !hasRelevantDatalabsData) {
  // Flag for honest decline — still augment to get Perplexity data, but be transparent
  const gapType = salaryPattern.test(originalQuery) ? 'salary/compensation' :
                   techStackPattern.test(originalQuery) ? 'tech stack' : 'hiring data';

  return [{
    json: {
      ...input,
      _opt122_needs_augmentation: true,
      _opt122_reasons: [`BLOCK2-DATA-001/D3: Known data gap (${gapType}) — honest decline flagged`],
