let needsAugmentation = false;
let augmentationReasons = [];



const aiGeneralOnly = sources.length > 0 &&
  sources.every(s => getSourceText(s).includes('general knowledge'));
const noSources = sources.length === 0;

// L4-SPEED: Condition 0 REMOVED (redundant with Condition 12 R2 short-response check)

// Condition 1 (L4-simplified): No sources with short output
// AI-GK case removed — caught by Ralph R1 (Condition 11) regardless of length
if (noSources && output.length < 300) {
  needsAugmentation = true;
  augmentationReasons.push('No sources + short output (<300 chars)');
}

// Condition 2: Explicit data gap signals
const dataGapSignals = [
  'no data available', 'no information found', 'unable to find',
  "don't have specific data", "couldn't find specific", "couldn't find data",
  "could not find", 'no results found', 'no specific data',
  'not available in our', 'not in our database', "i couldn't find"
];
const outputLower = output.toLowerCase();
const hasDataGap = dataGapSignals.some(s => outputLower.includes(s));
if (hasDataGap && output.length < 500) {
  needsAugmentation = true;
  augmentationReasons.push('Data gap detected in short response');
}

// L4-SPEED: Condition 3 REMOVED (salary/compensation already handled by BLOCK2-DATA-001 early return)

// Condition 4: success=false from upstream
if (input.success === false) {
  needsAugmentation = true;
  augmentationReasons.push('Upstream reported success=false');
}

