// ========================
// 0. STRIP JSON WRAPPERS (Iter 2 — Fix 3)
// ========================

function stripJsonWrappers(text) {
  let cleaned = text;
  const trimmed = cleaned.trim();

  // Early exit: not JSON-like
  if (!trimmed.startsWith('{')) return cleaned;

  // Strategy 1: Full JSON parse — handles {"output": "...", "sources": [...], ...}
  try {
    const parsed = JSON.parse(trimmed);
    if (parsed.output && typeof parsed.output === 'string') {
      cleaned = parsed.output;
      // Unescape if the output itself was double-escaped
      if (cleaned.includes('\\n')) {
        cleaned = cleaned.replace(/\\n/g, '\n').replace(/\\"/g, '"');
      }
      return cleaned;
    }
    // Also handle {"response": "..."} or {"answer": "..."}
    if (parsed.response && typeof parsed.response === 'string') return parsed.response;
    if (parsed.answer && typeof parsed.answer === 'string') return parsed.answer;
  } catch(e) {
    // Not valid JSON — fall through to regex approaches
  }

  // Strategy 2: Regex for truncated JSON — starts with {"output": " but parse failed
  const jsonPrefixMatch = cleaned.match(/^\s*\{\s*"output"\s*:\s*"([\s\S]*)/);
  if (jsonPrefixMatch) {
    let inner = jsonPrefixMatch[1];
    // Strip trailing JSON fields: ", "sources": [...], "success": true}
    inner = inner.replace(/",?\s*"(?:success|sources|raw_results|validation_criteria|fallback_used|fallback_strategy)"[\s\S]*$/m, '');
    // Strip trailing close: "}
    inner = inner.replace(/"\s*\}\s*$/, '');
    // Unescape JSON string escapes
    inner = inner.replace(/\\n/g, '\n').replace(/\\"/g, '"').replace(/\\\\/g, '\\').replace(/\\t/g, '\t');
    if (inner.length > 100) {
      cleaned = inner;
      return cleaned;
    }
  }

  // Strategy 3: Embedded "sources" JSON array at end of markdown
  cleaned = cleaned.replace(/\n\s*"sources"\s*:\s*\[\s*\{[\s\S]*?\}\s*\]\s*$/m, '');

  // Strategy 4: Trailing ", "success": true}" fragments
  cleaned = cleaned.replace(/",?\s*"success"\s*:\s*(true|false)\s*\}\s*$/m, '');

  return cleaned;
}

// ========================
// 1. REMOVE DUPLICATE PARAGRAPHS
// ========================

function removeDuplicateParagraphs(text) {
  const paragraphs = text.split(/\n\n+/);
  const seen = new Set();
  const unique = [];

  for (const para of paragraphs) {
    const normalized = para.toLowerCase().replace(/[*_#\-|]/g, '').replace(/\s+/g, ' ').trim();

    if (normalized.length < 10) {
      unique.push(para);
      continue;
    }

    let isDuplicate = false;
    for (const existing of seen) {
      if (normalized.length > 0 && existing.length > 0) {
        const shorter = normalized.length < existing.length ? normalized : existing;
        const longer = normalized.length >= existing.length ? normalized : existing;
        if (longer.includes(shorter.substring(0, Math.floor(shorter.length * 0.8)))) {
          isDuplicate = true;
          break;
        }
      }
    }

    if (!isDuplicate) {
      seen.add(normalized);
      unique.push(para);
    }
  }

  return unique.join('\n\n');
}

// ========================
// 2. REMOVE REDUNDANT SENTENCES
// ========================

function removeRedundantSentences(text) {
  const lines = text.split('\n');
  const seenFacts = new Set();
  const result = [];

  for (const line of lines) {
    const normalized = line.toLowerCase().replace(/[*_#\-|]/g, '').replace(/\s+/g, ' ').trim();

    if (normalized.length < 20 || /^#{1,4}\s/.test(line.trim()) || normalized === '') {
      result.push(line);
      continue;
    }

    const fundingMatch = normalized.match(/(\w+)\s+raised\s+\$[\d.]+[bmk]/i);
    if (fundingMatch) {
      const factKey = fundingMatch[0].toLowerCase();
      if (seenFacts.has(factKey)) {
        continue;
      }
      seenFacts.add(factKey);
    }

    result.push(line);
  }

  return result.join('\n');
}

// ========================
// 3. SMOOTH TRANSITIONS
// ========================

function smoothTransitions(text) {
  const paragraphs = text.split(/\n\n+/);
  if (paragraphs.length < 3) return text;

  const result = [paragraphs[0]];

  for (let i = 1; i < paragraphs.length; i++) {
    const prev = paragraphs[i - 1].toLowerCase();
    const curr = paragraphs[i].toLowerCase();

    const prevEndsWithData = /\d+[bmk%]|(?:series [a-e])|(?:round|funding|raised|invested)/i.test(prev.slice(-200));
    const currStartsWithNarrative = /^(?:the|in|when|while|meanwhile|additionally|furthermore|on the other hand)/i.test(curr.trim());

    if (prevEndsWithData && !currStartsWithNarrative && !curr.trim().startsWith('#') && !curr.trim().startsWith('-') && !curr.trim().startsWith('|')) {
      const firstWord = curr.trim().split(/\s/)[0];
      if (firstWord && !firstWord.startsWith('*') && curr.trim().length > 50) {
        const transitionWords = ['additionally', 'moreover', 'furthermore', 'meanwhile', 'in addition', 'building on', 'beyond'];
        const hasTransition = transitionWords.some(tw => curr.trim().toLowerCase().startsWith(tw));
        if (!hasTransition) {
          result.push(paragraphs[i]);
          continue;
        }
      }
    }

    result.push(paragraphs[i]);
  }

  return result.join('\n\n');
}

// ========================
// 4. DETECT QUERY TYPE
// ========================

function detectQueryType(query) {
  const q = query.toLowerCase();
  if (/\b(vc|vcs|investor|investors|fund|funds|angel|angels|check.?size|portfolio)\b/.test(q)) return 'investor';
  if (/\b(ecosystem|sector|industry|market|landscape)\b/.test(q)) return 'ecosystem';
  if (/\b(news|latest|recent|update|happened)\b/.test(q)) return 'news';
  if (/\b(funding|raised|series|round|investment)\b/.test(q)) return 'funding';
  if (/\b(compare|vs|versus|difference|between)\b/.test(q)) return 'comparative';
  if (/\b(why|how did|strategy|drove|path to|scaling)\b/.test(q)) return 'deep_research';
  return 'general';
}

// ========================
// 5. CLEAN UP METADATA LEAKS (Enhanced)
// ========================

function cleanMetadataLeaks(text) {
  let cleaned = text;

  cleaned = cleaned.replace(/\b_opt\d+_\w+\b/gi, '');
  cleaned = cleaned.replace(/\bbypass_type\b[:\s]*\w*/gi, '');
  cleaned = cleaned.replace(/\{[^}]*"_opt\d+[^}]*\}/g, '');

  // Remove leaked JSON keys in plaintext
  cleaned = cleaned.replace(/^\s*"success"\s*:\s*(true|false),?\s*$/gm, '');
  cleaned = cleaned.replace(/^\s*"output"\s*:\s*"/gm, '');

  // OPT-QFX: Strip system metadata patterns
  cleaned = cleaned.replace(/\bTotal results?:\s*\d+\s*\(route:\s*[\w_]+\)/gi, '');
  cleaned = cleaned.replace(/\broute[_:]?\s*(?:type|name)?[:\s]+(?:sector_search|company_funding|top_companies|investor_search|funding_rounds|company_detail|company_overview|founder_education|employee_ratings|quarterly_financials)\b/gi, '');
  cleaned = cleaned.replace(/\bquery_description[:\s]+[^\n]+/gi, '');
  cleaned = cleaned.replace(/\btotal_results?[:\s]+\d+/gi, '');

  // OPT-QFX: Replace database field names with natural language
  cleaned = cleaned.replace(/`?company_name`?/g, 'company name');
  cleaned = cleaned.replace(/`?sector\/tags`?/g, 'sector');
  cleaned = cleaned.replace(/`?last_funding_date`?/g, 'funding date');
  cleaned = cleaned.replace(/`?last_funding_type`?/g, 'funding stage');
  cleaned = cleaned.replace(/`?last_funding_amount`?/g, 'funding amount');
  cleaned = cleaned.replace(/`?amount_raised_in_usd`?/g, 'amount raised');
  cleaned = cleaned.replace(/`?hq_city`?/g, 'headquarters');
  cleaned = cleaned.replace(/`?founded_year`?/g, 'founding year');
  cleaned = cleaned.replace(/`?employee_count`?/g, 'employees');

  // OPT-QFX: Strip "share a Datalabs export" requests
  cleaned = cleaned.replace(/[Ii]f you can share[^.]*[Dd]atalabs[^.]*\./g, '');
  cleaned = cleaned.replace(/[Pp]lease (?:provide|share|send)[^.]*export[^.]*\./g, '');
  cleaned = cleaned.replace(/[Ii]f you (?:could|can) (?:provide|share)[^.]*(?:data|dataset|extract)[^.]*\./g, '');

  cleaned = cleaned.replace(/  +/g, ' ');
  cleaned = cleaned.replace(/\n{3,}/g, '\n\n');

  return cleaned;
}

// ========================
// OPT-162: ENTITY FRESHNESS — KNOWN REBRANDS
// ========================

function applyEntityFreshness(text) {
  if (typeof text !== 'string') return text;

  // Peak XV Partners (formerly Sequoia Capital India) — rebranded June 2023
  let peakXVMentioned = false;
  text = text.replace(/Sequoia Capital India(?! \(|\/ ?Peak)/gi, (match) => {
    if (!peakXVMentioned) {
      peakXVMentioned = true;
      return 'Peak XV Partners (formerly Sequoia Capital India)';
    }
    return 'Peak XV Partners';
  });

  // Also normalize if "Sequoia India" shorthand is used
  text = text.replace(/Sequoia India(?! \(|\/ ?Peak)/gi, () => {
    if (!peakXVMentioned) {
      peakXVMentioned = true;
      return 'Peak XV Partners (formerly Sequoia India)';
    }
    return 'Peak XV Partners';
  });

  // FM-V3-001 / OPT-176: Flipkart — add Walmart subsidiary context in investor/acquisition context
  const investorAcqContext = /\b(invest|acqui|portfolio|backed|subsidiary|parent company|owned by|stake in)\b/i;
  if (investorAcqContext.test(text)) {
    let flipkartDone = false;
    text = text.replace(/\bFlipkart\b(?! \(Walmart)/g, (match) => {
      if (!flipkartDone) {
        flipkartDone = true;
        return 'Flipkart (Walmart subsidiary)';
      }
      return match;
    });
  }

  // FM-V3-001 / OPT-176: PhonePe — independent since 2023
  if (/\b(Walmart|Flipkart)\b/i.test(text)) {
    let phonePeDone = false;
    text = text.replace(/\bPhonePe\b(?! \(independent)/g, (match) => {
      if (!phonePeDone) {
        phonePeDone = true;
        return 'PhonePe (independent since 2023)';
      }
      return match;
    });
  }

  // FM-V3-001 / OPT-176: BharatPe — flag stale CEO reference
  text = text.replace(/\bBharatPe\b[^.]*?\bAshneer Grover\b[^.]*?\bCEO\b/gi, (match) => {
    return match + ' [Note: Ashneer Grover departed BharatPe in 2022]';
  });
  text = text.replace(/\bCEO\b[^.]*?\bAshneer Grover\b[^.]*?\bBharatPe\b/gi, (match) => {
    return match + ' [Note: Ashneer Grover departed BharatPe in 2022]';
  });

  return text;
}

// ========================
// FM-V3-001 / OPT-172: AI-GK SOURCE PENALTY
// ========================

function detectAIGeneralKnowledge(text) {
  if (typeof text !== 'string') return text;

  const aigkPatterns = [
    /Based on general knowledge/i,
    /As an AI/i,
    /I don't have specific data/i,
    /generally speaking/i,
    /typically in Indian startups/i,
    /it is generally believed/i,
    /in general terms/i,
    /as is common in the industry/i
  ];

  let matchCount = 0;
  for (const p of aigkPatterns) {
    if (p.test(text)) matchCount++;
  }

  const result = { text, _fm_aigk_warning: false };

  if (matchCount > 2 && text.length < 800) {
    result._fm_aigk_warning = true;
  }

  if (matchCount > 3) {
    // Remove AI-GK filler sentences
    const fillerRegex = /(?:^|(?<=\.\s))(Based on general knowledge[^.]*\.|As an AI[^.]*\.|I don't have specific data[^.]*\.|Generally speaking[^.]*\.|Typically in Indian startups[^.]*\.)/gi;
    result.text = text.replace(fillerRegex, '').replace(/\n{3,}/g, '\n\n').trim();
  }

  return result;
}

// ========================
// FM-V3-001 / OPT-165: CURRENCY VALIDATION
// ========================

function validateCurrencyConsistency(text) {
  if (typeof text !== 'string') return text;

  const paragraphs = text.split(/\n\n+/);
  let flagged = false;

  for (const para of paragraphs) {
    const hasINR = /(?:₹|Rs\.?\s*\d|\d+\s*(?:crore|lakh|cr\b))/i.test(para);
    const hasUSD = /(?:\$\d|\d+\s*(?:million|billion|mn\b|bn\b))/i.test(para);

    if (hasINR && hasUSD) {
      const hasConversionContext = /(?:approximately|approx\.?|~|equivalent|around|roughly|converted|exchange rate)/i.test(para);
      if (!hasConversionContext) {
        flagged = true;
        break;
      }
    }
  }

  if (flagged) {
    const noteMarker = 'Note: Currency figures reflect original reporting and may mix INR/USD.';
    if (!text.includes(noteMarker)) {
      text = text.trimEnd() + '\n\n' + noteMarker;
    }
  }

  return text;
}

