// R4-FIX-001: Temporal context injection for freshness scoring
// When data points lack nearby date context, add temporal markers
function addTemporalContext(text) {
  // Don't modify short responses or responses that already have dates everywhere
  if (text.length < 1500) return text;

  const currentYear = new Date().getFullYear();
  const prevYear = currentYear - 1;

  // Check if response already has strong temporal context
  const yearMentions = (text.match(/20[2-3]\d/g) || []).length;
  const textBlocks = text.split('\n\n').length;
  if (yearMentions >= textBlocks * 0.7) return text; // Already well-dated

  // Add temporal context to data-heavy paragraphs that lack dates
  const paragraphs = text.split('\n\n');
  const enhanced = paragraphs.map(p => {
    // Skip if paragraph already has a year
    if (/20[2-3]\d/.test(p)) return p;
    // Skip very short paragraphs
    if (p.length < 100) return p;
    // Skip table rows and headers
    if (/^\|/.test(p.trim()) || /^#{1,3}\s/.test(p.trim())) return p;

    // Check if paragraph has data points (funding, revenue, growth)
    const hasDataPoints = /\$[\d,.]+\s*[BMKbmk]|₹[\d,.]+\s*(Cr|Lakh|crore)|\d+%\s*(growth|increase|decline|drop|rise)|raised\s+\$|funded\s+at|valuation\s+of|revenue\s+of/i.test(p);

    if (hasDataPoints) {
      // Add temporal note at end of data-heavy paragraph
      return p + ' *(as of ' + prevYear + '-' + currentYear + ' data)*';
    }
    return p;
  });

  return enhanced.join('\n\n');
}

