  const capMatches = query.match(/(?:[A-Z][a-z]+(?:\s+[A-Z][a-z]+)+)/g) || [];
  for (const match of capMatches) {
    if (!skipNames.has(match)) {
      addEntity(match, 'unknown', 'capitalized_name');
    }
  }

  // Sector keywords
  const sectorMatches = text.match(/(?:fintech|edtech|healthtech|agritech|SaaS|D2C|e-commerce|logistics|deeptech|clean\s?tech|climate\s?tech|gaming)/gi) || [];
  for (const sector of sectorMatches) {
    addEntity(sector.toLowerCase(), 'sector', 'keyword');
  }

  // Sort: companies first, then people, then unknown, then sectors
  entities.sort((a, b) => {
    const order = { company: 0, person: 1, unknown: 2, sector: 3 };
    return (order[a.type] ?? 2) - (order[b.type] ?? 2);
  });

  return entities.slice(0, 10);
}

