// === Query Type Classification ===
function classifyQuery(query) {
  const q = query.toLowerCase();
  if (/invest(ed|or|ment|s)|portfolio|backed|fund(ed|s)\s+by/i.test(q)) return 'investor_portfolio';
  if (/fund(ing|ed|raise)|series [a-f]|seed round|round size|capital raised/i.test(q)) return 'funding';
  if (/found(er|ed)|co-founder|started|who created|team behind/i.test(q)) return 'founder';
  if (/compar(e|ison)|vs\b|versus|difference between/i.test(q)) return 'comparison';
  if (/sector|industry|market|trend|landscape|ecosystem/i.test(q)) return 'sector';
  if (/revenue|business model|monetiz|profit|financials|valuation/i.test(q)) return 'business';
  if (/competitor|rival|alternative|similar to/i.test(q)) return 'competition';
  return 'general';
}

// === Dedup Guard: reject suggestions that mirror the original query ===
function isSimilarToQuery(suggestion, query) {
  const normalize = (s) => s.toLowerCase().replace(/[?!.,]/g, '').replace(/\s+/g, ' ').trim();
  const normSug = normalize(suggestion);
  const normQuery = normalize(query);
  if (normSug === normQuery) return true;
  const sugWords = new Set(normSug.split(' ').filter(w => w.length > 2));
  const queryWords = new Set(normQuery.split(' ').filter(w => w.length > 2));
  const intersection = [...sugWords].filter(w => queryWords.has(w)).length;
  const union = new Set([...sugWords, ...queryWords]).size;
  return union > 0 && intersection / union > 0.75;
}

const entities = extractEntities(output);
