    method: 'POST',
    url: ES_PROXY,
    body: proxyPayload,
    json: true,
    timeout: 5000,
  });

  const hits = result.hits?.hits || [];

  if (hits.length === 0) {
    return [{ json: { ...data, _opt_d_fallback: true, _opt_d_error: 'no_results' } }];
  }

  // Ambiguity check: if top hit score is close to second hit, entity is ambiguous
  if (hits.length > 1) {
