// OPT-D: Format Direct Response
// Template-based prose formatting — no LLM.
// ES field names: name, company_founders (string), founders (array of {name,person_uuid}),
//   amount_raised_in_usd, funding_round_count, description, team_size, founded_date (number/year)

const data = $json;
const d = data._opt_d_es_result || {};
