// Helpers
const fmt = (n) => {
  if (!n && n !== 0) return 'N/A';
  const num = Number(n);
  if (isNaN(num)) return String(n);
  if (num >= 1e9) return (num / 1e9).toFixed(1) + 'B';
  if (num >= 1e6) return (num / 1e6).toFixed(1) + 'M';
  if (num >= 1e3) return (num / 1e3).toFixed(0) + 'K';
  return num.toLocaleString();
};

const fmtDate = (dateStr) => {
  if (!dateStr) return 'N/A';
  try {
    const date = new Date(dateStr);
    return date.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
  } catch { return String(dateStr); }
};

// founded_date is a number (year) like 2014, not a date string
const yearStr = (y) => {
  if (!y) return 'N/A';
  return String(y);
};

// company_founders is a comma-separated string like "Harshil Mathur, Shashank Kumar"
// founders is an array of {name, person_uuid}
const getFounders = () => {
  if (d.company_founders) return d.company_founders;
  if (Array.isArray(d.founders) && d.founders.length > 0) {
    return d.founders.map(f => f.name).join(' and ');
