    let text = `Valuation data for **${companyName}** is not directly available in our database records.`;
    if (d.amount_raised_in_usd) text += ` The company has raised **$${fmt(d.amount_raised_in_usd)}** in total funding.`;
    if (d.last_funding_stage) text += ` Last funding stage: **${d.last_funding_stage}**.`;
    if (d.sector) text += ` Sector: ${d.sector}.`;
    if (d.city) text += ` Based in ${d.city}.`;
    return text;
  },

  company_basics: () => {
    let text = `**${companyName}**`;
    if (d.description) text += ` — ${d.description}`;
    else text += ' is an Indian startup';
    if (!text.endsWith('.')) text += '.';
    const details = [];
    if (d.sector) details.push(`**Sector:** ${d.sector}${d.sub_sector ? ' (' + d.sub_sector + ')' : ''}`);
    if (d.city) details.push(`**Headquarters:** ${d.city}`);
    if (d.founded_date) details.push(`**Founded:** ${yearStr(d.founded_date)}`);
    const founders = getFounders();
    if (founders !== 'N/A') details.push(`**Founders:** ${founders}`);
    if (d.amount_raised_in_usd) details.push(`**Total Funding:** $${fmt(d.amount_raised_in_usd)}`);
    if (d.team_size) details.push(`**Team Size:** ~${fmt(d.team_size)}`);
    if (details.length > 0) text += '\n\n' + details.join(' · ');
    return text;
  },

  headquarters: () => {
    if (d.city) {
      let text = `**${companyName}** is headquartered in **${d.city}**`;
      text += '.';
      if (d.sector) text += ` The company operates in the ${d.sector} sector.`;
      if (d.founded_date) text += ` Founded in ${yearStr(d.founded_date)}.`;
      return text;
    }
    return `Headquarters information for **${entity}** is not available in our records.`;
  },

  latest_round: () => {
    // For latest_round, check the funding array in the ES result
    const fundingArr = d.funding;
    if (Array.isArray(fundingArr) && fundingArr.length > 0) {
      // funding array is sorted by date in ES; take the last entry (most recent)
      const latest = fundingArr[fundingArr.length - 1];
      let text = `The latest funding round for **${companyName}** was a **${latest.funding_stage || latest.funding_type || 'round'}**`;
      if (latest.funding_amount) text += ` of **$${fmt(latest.funding_amount)}**`;
      if (latest.funding_date) text += ` in ${fmtDate(latest.funding_date)}`;
      text += '.';
      if (latest.investor_names) text += ` Investors: ${latest.investor_names}.`;
      return text;
    }
    // Fallback to top-level last_funding fields
    if (d.last_funding_stage || d.last_funding_amount) {
      let text = `The latest funding round for **${companyName}** was a **${d.last_funding_stage || 'round'}**`;
      if (d.last_funding_amount) text += ` of **$${fmt(d.last_funding_amount)}**`;
      if (d.last_funding_date) text += ` in ${fmtDate(d.last_funding_date)}`;
      text += '.';
      return text;
    }
    return `Latest funding round data for **${entity}** is not available in our records.`;
  },

  founded_date: () => {
    let text = `**${companyName}** was founded in **${d.founded_date ? yearStr(d.founded_date) : 'N/A'}**`;
    if (d.city) text += ` in ${d.city}`;
    text += '.';
    const founders = getFounders();
    if (founders !== 'N/A') text += ` Founders: **${founders}**.`;
    if (d.description) text += ` ${d.description}`;
    if (d.sector) text += ` Sector: ${d.sector}.`;
    return text;
  },
};

// Generate response
const templateFn = templates[queryType];
const output = templateFn ? templateFn() : `Information about **${entity}** retrieved from Datalabs.`;

// Type-dependent follow-up suggestions
const suggestionsByType = {
  founder: [`How much has ${companyName} raised?`, `${companyName} latest funding round`, `Compare ${companyName} with competitors`],
  funding_total: [`${companyName} latest funding round`, `Who invested in ${companyName}?`, `${companyName} valuation`],
  valuation: [`${companyName} funding history`, `Who are ${companyName}'s investors?`, `Compare ${companyName} valuation with peers`],
  company_basics: [`Who founded ${companyName}?`, `${companyName} funding details`, `${companyName} competitors`],
  headquarters: [`Tell me more about ${companyName}`, `Who founded ${companyName}?`, `${companyName} funding`],
  latest_round: [`${companyName} total funding`, `Who are ${companyName}'s founders?`, `${companyName} valuation`],
  founded_date: [`Who founded ${companyName}?`, `${companyName} funding history`, `What does ${companyName} do?`],
};

const responseTimeMs = Date.now() - startTime;

return [{ json: {
  output: output,
  sources: [{title: 'Datalabs (verified company records)', uri: 'https://datalabs.inc42.com/company/' + (d.slug || ''), source: 'Datalabs'}],
  suggestions: suggestionsByType[queryType] || [`Tell me more about ${entity}`, `${entity} funding`, `${entity} competitors`],
  chatInput: chatInput,
  meta: {
    mode: 'fast',
    response_time_ms: responseTimeMs,
    data_freshness: { source: 'elasticsearch', index: data._opt_d_es_index || 'datalabs_companies' },
  },
  _opt_d_type: queryType,
  _opt_d_entity: entity,
  _opt_d_mode: 'fast',
  success: true,
}}];

// SEC-01: Input Validation Gateway + SEC-04: Rate Limiting
// Validates webhook input and enforces rate limits before any processing.

const input = $input.first().json;
const body = input.body || input;
const chatInput = body.chatInput;

// --- SEC-04: Rate Limiting ---
const staticData = $getWorkflowStaticData('global');
if (!staticData._rateLimits) staticData._rateLimits = {};

const headers_rl = input.headers || body.headers || {};
const rawIp = headers_rl['x-forwarded-for'] || headers_rl['x-real-ip'] || headers_rl['cf-connecting-ip'] || 'unknown';
const clientIp = rawIp.split(',')[0].trim();

const now = Date.now();

// Cleanup stale entries (~5% of requests)
if (Math.random() < 0.05) {
  const cutoff = now - 3600000;
  for (const [ip, data] of Object.entries(staticData._rateLimits)) {
    if (!data.requests || data.requests.length === 0) { delete staticData._rateLimits[ip]; continue; }
    data.requests = data.requests.filter(ts => ts > cutoff);
    if (data.requests.length === 0) delete staticData._rateLimits[ip];
  }
}

if (!staticData._rateLimits[clientIp]) staticData._rateLimits[clientIp] = { requests: [] };
const ipData = staticData._rateLimits[clientIp];
ipData.requests.push(now);

// Per-minute check (15 req/min)
const recentMinute = ipData.requests.filter(ts => ts > now - 60000);
if (recentMinute.length > 15) {
  return [{ json: { error: true, output: "Rate limit exceeded. Please wait a moment before trying again.", _rejected: 'rate_limited', _sec04: true } }];
}

// Per-hour check (100 req/hr)
const recentHour = ipData.requests.filter(ts => ts > now - 3600000);
if (recentHour.length > 100) {
  return [{ json: { error: true, output: "You have exceeded the hourly request limit. Please try again later.", _rejected: 'rate_limited', _sec04: true } }];
}
ipData.requests = recentHour;

// --- SEC-01: Input Validation ---
if (chatInput === undefined || chatInput === null) {
  return [{ json: { error: true, output: "Please provide a question using the 'chatInput' field.", _rejected: 'missing_input', _sec01: true } }];
}
if (typeof chatInput !== 'string') {
  return [{ json: { error: true, output: "Invalid input type. Please send your question as text.", _rejected: 'invalid_type', _sec01: true } }];
}
if (chatInput.trim().length === 0) {
  return [{ json: { error: true, output: "Please provide a question.", _rejected: 'empty_input', _sec01: true } }];
}
if (chatInput.length > 2000) {
  return [{ json: { error: true, output: "Your question is too long. Please keep it under 2000 characters.", _rejected: 'too_long', _sec01: true } }];
}

const sanitized = chatInput
  .replace(/<script\b[^<]*(?:(?!<\/script>)<[^<]*)*<\/script>/gi, '')
  .replace(/<[^>]*>/g, '')
  .trim();
const cleaned = sanitized.replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '');

if (cleaned.length < 2) {
  return [{ json: { error: true, output: "Please provide a valid question.", _rejected: 'stripped_empty', _sec01: true } }];
}

const normalized = cleaned.normalize('NFC');

const result = { ...input };
if (result.body) { result.body = { ...result.body, chatInput: normalized }; }
else { result.chatInput = normalized; }
result._sec01_validated = true;
result._sec04_ip = clientIp;

return [{ json: result }];

// EDGE-01: Sub-Workflow Health Check
// Detects failed or empty sub-workflow results after Merge
// Flags for Perplexity fallback if both sources are degraded

const items = $input.all();
const healthReport = {
  datalabs: { status: 'unknown', dataLength: 0 },
  inc42Context: { status: 'unknown', dataLength: 0 },
  overallHealth: 'healthy',
  failedSources: [],
  degradedSources: []
};

for (const item of items) {
  const data = item.json;

  if (data.error || data.errorMessage || data.error_type) {
    healthReport.failedSources.push({
      source: data._source || 'unknown',
      error: data.errorMessage || data.error || data.error_type,
    });
    continue;
  }

  if (data.output && typeof data.output === 'string') {
    const isErrorResponse =
      data.output.includes('AI Agent error') ||
      data.output.includes('No output from AI Agent') ||
      data.output.includes('Failed to parse') ||
      data.output.includes('Unknown query type') ||
      data.output.length < 20;

    if (isErrorResponse) {
      healthReport.degradedSources.push({
        source: 'sub-workflow',
        reason: 'Error pattern detected',
        outputPreview: data.output.substring(0, 100)
      });
    }
  }

  if (!data.output && !data.data && !data.results && !data.items) {
    healthReport.degradedSources.push({
      source: 'sub-workflow',
      reason: 'Empty result'
    });
  }
}

const totalFailures = healthReport.failedSources.length + healthReport.degradedSources.length;
if (totalFailures >= 2) {
  healthReport.overallHealth = 'critical';
} else if (totalFailures === 1) {
  healthReport.overallHealth = 'degraded';
}

const output = items.map(item => ({
  json: {
    ...item.json,
    _edge01_health: healthReport.overallHealth,
    _edge01_force_augmentation: healthReport.overallHealth === 'critical',
  }
}));

return output;

// =============================================================================
// OPT-155c: Query Resolver (Phase 2+3 Rewrite)
// Resolves pronouns and references using session entity context
// Tier 1: Regex (~0ms) — handles pronouns, company refs (5 reliable patterns)
// Tier 2: LLM (~500-900ms) — always-on for remaining unresolved multi-turn queries
// Architecture: LangChain ContextualizeQ + Quivr entity preservation + NVIDIA guardrails
// =============================================================================

const input = $input.first().json;
const chatInput = (input.chatInput || '').trim();
const sessionEntities = input._session_entities || [];
const sessionContext = input._session_context || '';

// Pass-through if no session entities or no query
if (sessionEntities.length === 0 || !chatInput) {
  return [{
    json: {
      ...input,
      _original_query: chatInput,
      _resolved_query: null,
      _resolution_method: 'none',
      _resolution_entity: null
    }
  }];
}

// Prioritize company entities for pronoun resolution (companies before people)
const companyEntities = sessionEntities.filter(e => e.type === 'company');
const personEntities = sessionEntities.filter(e => e.type === 'person');
// Recency-biased: session entities are chronological (oldest first), last = most recent
// First company entity = topic of most recent query (OPT-155b puts query entities first)
const mostRecentCompany = companyEntities.length > 0 ? companyEntities[0] : null;
const mostRecentPerson = personEntities.length > 0 ? personEntities[0] : null;
const primaryEntity = mostRecentCompany?.name || mostRecentPerson?.name || sessionEntities[sessionEntities.length - 1]?.name || '';

let resolved = chatInput;
let method = 'none';
let resolvedEntity = null;

// --- Tier 1: Regex Resolution (Fast Path) ---
// 5 reliable patterns that save an LLM call for ~60-70% of follow-ups.
// Removed: ordinals, "which one", topic continuation — LLM handles those better.

// Guard: Skip pronoun resolution if query already contains a named entity
const queryLower = chatInput.toLowerCase();
const entityAlreadyInQuery = sessionEntities.some(e =>
  e.name && queryLower.includes(e.name.toLowerCase())
);
// Stoplist-based proper noun detection (Phase 0 fix)
const COMMON_SENTENCE_STARTERS = new Set([
  'what', 'when', 'where', 'which', 'who', 'whom', 'whose', 'how', 'why',
  'tell', 'show', 'give', 'find', 'list', 'get', 'compare', 'describe', 'explain',
  'their', 'theirs', 'they', 'them', 'these', 'those', 'this', 'that',
  'and', 'but', 'the', 'can', 'did', 'does', 'has', 'have', 'had', 'will',
  'would', 'could', 'should', 'are', 'was', 'were', 'been', 'being', 'his',
  'her', 'its', 'also', 'more', 'most', 'some', 'any', 'all', 'now', 'not',
  'about', 'from', 'with', 'for', 'into', 'over', 'after', 'before', 'between',
  'same', 'each', 'every', 'both', 'many', 'much', 'very', 'yes', 'sure',
  'top', 'best', 'first', 'last', 'next', 'new', 'old', 'please', 'thanks',
  'okay', 'like', 'want', 'need', 'know', 'think', 'just', 'still'
]);
const properNounMatches = (chatInput.match(/\b[A-Z][a-z]{2,}(?:\s+[A-Z][a-z]+)*\b/g) || [])
  .filter(w => !COMMON_SENTENCE_STARTERS.has(w.split(' ')[0].toLowerCase()));
const queryHasProperNoun = properNounMatches.length > 0;
const skipPronounResolution = entityAlreadyInQuery || queryHasProperNoun;

// 1. Possessive pronouns: their, its -> entity's
if (!skipPronounResolution && /\b(their|its)\b/i.test(resolved) && primaryEntity) {
  resolved = resolved.replace(/\b(their|its)\b/gi, `${primaryEntity}'s`);
  method = 'regex';
  resolvedEntity = primaryEntity;
}

// 2. Person possessive pronouns: his, her -> person's
if (method === 'none' && !skipPronounResolution && /\b(his|her)\b/i.test(resolved) && mostRecentPerson) {
  resolved = resolved.replace(/\b(his|her)\b/gi, `${mostRecentPerson.name}'s`);
  method = 'regex';
  resolvedEntity = mostRecentPerson.name;
}

// 3. Company references: the company, that startup, etc. -> entity
if (method === 'none' && /\b(the company|that company|the startup|that startup|this company|this startup)\b/i.test(resolved) && primaryEntity) {
  resolved = resolved.replace(/\b(the company|that company|the startup|that startup|this company|this startup)\b/gi, primaryEntity);
  method = 'regex';
  resolvedEntity = primaryEntity;
}

// 4. Subject pronouns: "they" in question/action patterns
if (method === 'none' && primaryEntity && !skipPronounResolution) {
  const questionThey = /(?:when|where|how|why|did|has|have|will|would|could|should|can|do|does|is|are|was|were)\s+they\b/i;
  const actionThey = /\bthey\s+(?:raised|founded|acquired|launched|reported|generated|grew|expanded|filed|reached|announced|received|secured|closed|merged|pivoted|entered|went|have|had|are|were|will|plan)/i;
  const startThey = /^they\s+/i;

  if (questionThey.test(resolved) || actionThey.test(resolved) || startThey.test(resolved)) {
    resolved = resolved.replace(/\bthey\b/gi, primaryEntity);
    method = 'regex';
    resolvedEntity = primaryEntity;
  }
}

// 5. Object pronouns: "them" in any position
if (method === 'none' && !skipPronounResolution && primaryEntity) {
  if (/\bthem\b/i.test(resolved)) {
    resolved = resolved.replace(/\bthem\b/gi, primaryEntity);
    method = 'regex';
    resolvedEntity = primaryEntity;
  }
}

// --- Tier 2: Deterministic Query Rewriter (Multi-Turn) ---
// Handles follow-up queries by pattern-matching and template substitution.
// Note: LLM rewriter removed — $env.OPENAI_API_KEY not accessible in Code nodes.
if (method === 'none' && sessionEntities.length > 0 && sessionContext) {
  const lastQueryMatch = sessionContext.match(/User: ([^\n]+)(?:\nAssistant:|\nTopics|$)/g);
  const lastQueries = (lastQueryMatch || []).map(m => m.replace(/^User: /, '').replace(/\n(Assistant:|Topics).*$/, '').trim());
  const lastUserQuery = lastQueries.length > 0 ? lastQueries[lastQueries.length - 1] : '';

  if (lastUserQuery) {
    const lowerInput = chatInput.toLowerCase().trim().replace(/\?$/, '');

    // Pattern A: Year swap — "What about in 2025?"
    const yearSwapMatch = lowerInput.match(/^(?:what|how|and what|and how|and|ok)\s*(?:about)?\s*(?:in\s+)?(\d{4})$/);
    if (yearSwapMatch) {
      const newYear = yearSwapMatch[1];
      const yearInLast = lastUserQuery.match(/\b(20\d{2})\b/);
      if (yearInLast) {
        resolved = lastUserQuery.replace(/\b20\d{2}\b/, newYear);
        method = 'template_year_swap';
        resolvedEntity = primaryEntity || null;
      }
    }

    // Pattern B: Sector swap — "What about edtech?"
    if (method === 'none') {
      const SECTORS = 'fintech|edtech|healthtech|agritech|saas|ai|deeptech|e-?commerce|logistics|ev|cleantech|foodtech|gaming|proptech|insurtech|legaltech|hrtech|biotech|spacetech|cybersecurity';
      const topicSwapMatch = lowerInput.match(/^(?:what|how|and what|and how|and|ok)\s*(?:about|for|regarding)?\s+(.+)$/);
      if (topicSwapMatch) {
        const newTopic = topicSwapMatch[1].trim();
        const sectorRe = new RegExp('\\b(' + SECTORS + ')\\b', 'gi');
        const lastSectors = lastUserQuery.match(sectorRe);
        if (lastSectors && sectorRe.test(newTopic)) {
          resolved = lastUserQuery.replace(new RegExp('\\b(' + SECTORS + ')\\b', 'gi'), newTopic);
          method = 'template_sector_swap';
          resolvedEntity = null;
        } else {
          const entityNames = sessionEntities.filter(e => e.type === 'company' || e.type === 'person').map(e => e.name);
          for (const eName of entityNames) {
            if (lastUserQuery.toLowerCase().includes(eName.toLowerCase())) {
              resolved = lastUserQuery.replace(new RegExp(eName.replace(/[.*+?^${}()|[\\]\\]/g, '\\$&'), 'gi'), newTopic);
              method = 'template_entity_swap';
              resolvedEntity = newTopic;
              break;
            }
          }
        }
      }
    }

    // Pattern C: Sector carry-forward for short follow-ups  
    if (method === 'none' && chatInput.split(' ').length <= 6) {
      const SECTORS_RE = /\b(fintech|edtech|healthtech|agritech|saas|ai|deeptech|e-?commerce|logistics|ev|cleantech|foodtech|gaming)\b/i;
      const lastHadSector = SECTORS_RE.test(lastUserQuery);
      const currentHasSector = SECTORS_RE.test(chatInput);
      if (lastHadSector && !currentHasSector) {
        const sectorMatch = lastUserQuery.match(SECTORS_RE);
        if (sectorMatch) {
          resolved = chatInput.replace(/\?$/, '') + ' in ' + sectorMatch[0] + '?';
          method = 'template_sector_carry';
          resolvedEntity = null;
        }
      }
    }
  }
}

// Output
const wasResolved = resolved !== chatInput;
return [{
  json: {
    ...input,
    chatInput: wasResolved ? resolved : chatInput,
    _original_query: chatInput,
    _resolved_query: wasResolved ? resolved : null,
    _resolution_method: method,
    _resolution_entity: resolvedEntity
  }
}];

// Parallel Fetch v3: Uses require('https') + reduced timeouts + hard cap
// Calls 3 sub-workflow wrapper webhooks simultaneously via Promise.all()

const chatInput = $json.chatInput || $json.body?.chatInput || '';
const BASE_HOST = 'automations.ink42.com';
const debug = [];

// Compute dynamic date range for Inc42 Updates (last 90 days)
const now = new Date();
const from90 = new Date(now);
from90.setDate(from90.getDate() - 90);
const updatesFrom = from90.toISOString().split('T')[0];
const updatesTo = now.toISOString().split('T')[0];

// HTTP POST helper using require('https')
function httpPost(path, body, timeoutMs) {
  const https = require('https');
  return new Promise((resolve) => {
    const postData = JSON.stringify(body);
    const options = {
      hostname: BASE_HOST,
      port: 443,
      path: '/webhook/' + path,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Content-Length': Buffer.byteLength(postData)
      },
      timeout: timeoutMs || 45000
    };

    const req = https.request(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        try {
          // Handle potential NDJSON (multiple JSON lines)
          const firstLine = data.trim().split('\n')[0];
          resolve(JSON.parse(firstLine));
        } catch (e) {
          resolve({ _parse_error: e.message, _raw_preview: data.slice(0, 200) });
        }
      });
    });

    req.on('error', (e) => {
      resolve({ _fetch_error: 'request_error: ' + e.message });
    });

    req.on('timeout', () => {
      req.destroy();
      resolve({ _fetch_error: 'timeout' });
    });

    req.write(postData);
    req.end();
  });
}

// Fire all 3 requests in parallel with reduced timeouts
// Datalabs: 25s (was 45s), Context: 20s (was 30s), Updates: 15s (was 30s)
// Hard cap: 25s total — proceed with whatever data arrived
const HARD_CAP_MS = 25000;
const partials = { d: null, c: null, u: null };
let datalabsResp, contextResp, updatesResp;
try {
  const fetchPromise = Promise.all([
    httpPost('fo-datalabs-parallel-7a2b', { query: chatInput }, 25000)
      .then(r => { partials.d = r; return r; }),
    httpPost('fo-inc42ctx-parallel-8c3d', { query: chatInput, from: '2024', to: '2026' }, 20000)
      .then(r => { partials.c = r; return r; }),
    httpPost('fo-inc42upd-parallel-9e4f', { query: chatInput, from: updatesFrom, to: updatesTo }, 15000)
      .then(r => { partials.u = r; return r; })
  ]);
  const hardCap = new Promise((resolve) => {
    setTimeout(() => resolve('HARD_CAP'), HARD_CAP_MS);
  });
  const raceResult = await Promise.race([fetchPromise, hardCap]);
  if (raceResult === 'HARD_CAP') {
    debug.push('parallel_fetch: HARD_CAP at ' + HARD_CAP_MS + 'ms, partials: d=' + !!partials.d + ' c=' + !!partials.c + ' u=' + !!partials.u);
  } else {
    debug.push('parallel_fetch: all 3 resolved');
  }
  datalabsResp = partials.d || { _fetch_error: 'hard_cap' };
  contextResp = partials.c || { _fetch_error: 'hard_cap' };
  updatesResp = partials.u || { _fetch_error: 'hard_cap' };
} catch (e) {
  debug.push('parallel_fetch_error: ' + (e.message || String(e)));
  datalabsResp = { _fetch_error: 'promise_error' };
  contextResp = { _fetch_error: 'promise_error' };
  updatesResp = { _fetch_error: 'promise_error' };
}

// Log fetch results for debugging
for (const [name, resp] of [['datalabs', datalabsResp], ['context', contextResp], ['updates', updatesResp]]) {
  if (resp && resp._fetch_error) {
    debug.push(name + '_error: ' + resp._fetch_error);
  } else if (resp && resp._parse_error) {
    debug.push(name + '_parse_error: ' + resp._parse_error);
  } else {
    const keys = resp ? Object.keys(resp).slice(0, 5).join(',') : 'null';
    debug.push(name + '_ok: keys=' + keys);
  }
}

// Format into sections (same logic as FO-Aggregate)
const results = [datalabsResp, contextResp, updatesResp];
const labels = [
  'Datalabs Data (Verified Records)',
  'Inc42 Articles & Context',
  'Recent Inc42 News & Updates'
];

const sections = [];
const allSources = [];

// OPT-QFX: Temporal pre-filter — if query mentions "last N months/years", filter results by date
const temporalMatch = chatInput.match(/(?:last|past|recent)\s+(\d+)\s+(month|year|week|day)/i);
let temporalCutoff = null;
if (temporalMatch) {
  const count = parseInt(temporalMatch[1]);
  const unit = temporalMatch[2].toLowerCase();
  const cutoff = new Date();
  if (unit.startsWith('month')) cutoff.setMonth(cutoff.getMonth() - count);
  else if (unit.startsWith('year')) cutoff.setFullYear(cutoff.getFullYear() - count);
  else if (unit.startsWith('week')) cutoff.setDate(cutoff.getDate() - count * 7);
  else cutoff.setDate(cutoff.getDate() - count);
  temporalCutoff = cutoff.toISOString().split('T')[0];
  debug.push('temporal_cutoff: ' + temporalCutoff);
}

for (let i = 0; i < results.length; i++) {
  const j = results[i];
  if (!j || j._fetch_error || j._parse_error) continue;

  let content = '';

  if (j.output && typeof j.output === 'string' && j.output.length > 30) {
    content = j.output;
  } else if (j.text && typeof j.text === 'string' && j.text.length > 30) {
    content = j.text;
  } else if (j.response && typeof j.response === 'string' && j.response.length > 30) {
    content = j.response;
  } else if (Array.isArray(j.results) && j.results.length > 0) {
    const routeType = j.route_type || 'unknown';
    const total = j.total_results || j.results.length;
    const desc = j.query_description || '';
    const lines = [];
    debug.push('datalabs_route: ' + routeType + ', total: ' + total);
    lines.push('');
    let filteredResults = j.results.slice(0, 50);
    if (temporalCutoff && filteredResults.some(r => r.last_funding_date || r.date)) {
      const before = filteredResults.length;
      filteredResults = filteredResults.filter(r => {
        const d = r.last_funding_date || r.date || '';
        return !d || d >= temporalCutoff;
      });
      debug.push('temporal_filter: ' + before + ' -> ' + filteredResults.length);
    }
    filteredResults = filteredResults.slice(0, 20);
    // V3.5 Tier 0: Route metadata header
    if (j.company_name && j.total_raised_formatted) {
      lines.push(j.company_name + ': ' + j.total_raised_formatted + ' total funding');
    }
    if (j.investor_name) {
      lines.push('Investor: ' + j.investor_name);
    }
    if (j.summary) {
      lines.push('Summary: ' + j.summary);
    }
    // V3.5 Tier 0: Route-specific formatters
    const fmtFunding = (r) => {
      const parts = [];
      if (r.funding_type) parts.push(r.funding_type);
      if (r.amount_usd) parts.push('$' + (r.amount_usd / 1e6).toFixed(1) + 'M');
      if (r.funding_date) parts.push(r.funding_date.split('T')[0]);
      if (r.investors) parts.push('Investors: ' + r.investors);
      return parts.join(' | ');
    };
    const fmtInvestor = (r) => {
      const parts = [];
      if (r.company_name) parts.push(r.company_name);
      if (r.funded_sector || r.company_sector) parts.push('Sector: ' + (r.funded_sector || r.company_sector));
      if (r.funding_type) parts.push(r.funding_type);
      if (r.amount_raised_in_usd) parts.push('$' + (r.amount_raised_in_usd / 1e6).toFixed(1) + 'M');
      if (r.funding_date) parts.push(r.funding_date.split('T')[0]);
      if (r.investor_names) parts.push('Investors: ' + r.investor_names.replace(/\u00a0/g, ' '));
      return parts.join(' | ');
    };
    const fmtFounder = (r) => {
      const parts = [];
      if (r.founder_name) parts.push(r.founder_name);
      if (r.company_name) parts.push('(' + r.company_name + ')');
      if (r.education) parts.push('Education: ' + r.education);
      return parts.join(' | ');
    };
    const fmtCompany = (r) => {
      const rName = r.company_name || r.name || r.investor_name || 'Unknown';
      const parts = [rName];
      if (r.sector) parts.push('Industry: ' + r.sector);
      if (r.hq_city || r.city) parts.push('Headquarters: ' + (r.hq_city || r.city));
      if (r.total_funding_usd || r.amount_raised_in_usd) {
        const amt = r.total_funding_usd || r.amount_raised_in_usd;
        parts.push('Total Funding: $' + (amt / 1000000).toFixed(1) + 'M');
      }
      if (r.last_funding_amount) parts.push('Last Round: $' + (r.last_funding_amount / 1000000).toFixed(1) + 'M');
      if (r.last_funding_type) parts.push('Stage: ' + r.last_funding_type);
      if (r.last_funding_date) parts.push('Date: ' + r.last_funding_date);
      if (r.founded_year || r.founded_date) parts.push('Founded: ' + (r.founded_year || r.founded_date));
      if (r.employee_count) parts.push('Employees: ' + r.employee_count);
      if (r.revenue) parts.push('Revenue: ' + r.revenue);
      return parts.join(' | ');
    };
    const routeFormatters = {
      company_funding: fmtFunding,
      investor_portfolio: fmtInvestor,
      funding_rounds: fmtInvestor,
      founder_education: fmtFounder,
      faceted_search: fmtCompany,
      top_companies: fmtCompany,
      sector_search: fmtCompany,
      company_comparison: fmtCompany
    };
    const formatter = routeFormatters[routeType] || fmtCompany;
    for (const r of filteredResults) {
      const formatted = formatter(r);
      if (formatted) lines.push('- ' + formatted);
    }
    content = lines.join('\n');
  } else if (j.data && typeof j.data === 'object') {
    const d = j.data;
    const lines = [];
    if (j.company_name) lines.push('Company: ' + j.company_name);
    if (d.description) lines.push('Description: ' + d.description);
    if (d.company_type) lines.push('Type: ' + d.company_type);
    if (d.founded_date) lines.push('Founded: ' + d.founded_date);
    if (d.founders_info) {
      const founders = d.founders_info.map(f => f.name || f.full_name).filter(Boolean);
      if (founders.length) lines.push('Founders: ' + founders.join(', '));
    }
    if (d.funding_summary) lines.push('Funding: ' + JSON.stringify(d.funding_summary));
    if (d.sector) lines.push('Sector: ' + (typeof d.sector === 'object' ? d.sector.name || '' : d.sector));
    if (d.hq_city) lines.push('HQ: ' + d.hq_city);
    if (d.employee_count) lines.push('Employees: ' + d.employee_count);
    if (d.website) lines.push('Website: ' + d.website);
    if (d.ipo_status) lines.push('IPO Status: ' + d.ipo_status);
    if (d.tags) lines.push('Tags: ' + (Array.isArray(d.tags) ? d.tags.join(', ') : d.tags));
    if (d.funding_overview) lines.push('Funding Overview: ' + JSON.stringify(d.funding_overview));
    if (d.overview) lines.push('Overview: ' + (typeof d.overview === 'string' ? d.overview : JSON.stringify(d.overview)).slice(0, 500));
    if (lines.length > 2) {
      const { route_type, total_results, query_description, total, ...cleanData } = (typeof d === 'object' ? d : {});
      content = lines.join('\n') + '\n\nAdditional details: ' + JSON.stringify(cleanData).slice(0, 3000);
    }
  } else if (j.result && typeof j.result === 'string' && j.result.length > 30) {
    content = j.result;
  }

  if (content && content.length > 30) {
    sections.push('## ' + labels[i] + '\n' + content);
  }

  if (Array.isArray(j.sources)) {
    allSources.push(...j.sources);
  }
}

const contextBlock = sections.length > 0
  ? sections.join('\n\n')
  : 'No data retrieved from internal sources.';

// Carry forward upstream data
let body = {};
let classifyData = {};
let sessionContext = '';

try { body = $('Webhook').first().json.body || {}; } catch(e) {
  try { body = $('OPT-004: Check Cache').first().json.body || {}; } catch(e2) {}
}
try { classifyData = $('Classify Query Type').first().json || {}; } catch(e) {}
try { sessionContext = $('OPT-155c: Query Resolver').first().json._session_context || ''; } catch(e) {
  try { sessionContext = $('OPT-155a: Read Session').first().json._session_context || ''; } catch(e2) {}
}


// S-2b: Extract company/investor slugs from Datalabs response (Sprint 2)
const _company_slugs = {};
if (datalabsResp && !datalabsResp._fetch_error) {
  // Single company response: company_slug at top level
  if (datalabsResp.company_name && datalabsResp.company_slug) {
    _company_slugs[datalabsResp.company_name.toLowerCase()] = datalabsResp.company_slug;
  }
  // Investor slug
  if (datalabsResp.investor_name && datalabsResp.investor_slug) {
    _company_slugs[datalabsResp.investor_name.toLowerCase()] = datalabsResp.investor_slug;
  }
  // Results array: each item may have slug or company_slug
  if (Array.isArray(datalabsResp.results)) {
    for (const r of datalabsResp.results) {
      const name = (r.company_name || r.name || r.investor_name || '').toLowerCase();
      const slug = r.slug || r.company_slug || r.investor_slug || '';
      if (name && slug) _company_slugs[name] = slug;
    }
  }
  // Nested data object (company_detail route)
  if (datalabsResp.data && typeof datalabsResp.data === 'object') {
    const d = datalabsResp.data;
    if (d.slug && datalabsResp.company_name) {
      _company_slugs[datalabsResp.company_name.toLowerCase()] = d.slug;
    }
  }
  debug.push('slugs_extracted: ' + Object.keys(_company_slugs).length);
}

return [{
  json: {
    chatInput: chatInput || body?.chatInput || '',
    body: body,
    data: contextBlock,
    _prefetched_sources: allSources,
    _prefetched_section_count: sections.length,
    _session_context: sessionContext,
    _classify_type: classifyData._classify_type || classifyData.query_type || '',
    _cache_status: classifyData._cache_status || 'miss',
    _mode: classifyData._mode || '',
    _parallel_fetch_debug: debug.join('; '),
    _company_slugs: _company_slugs
  }
}];

// env: Inject secrets while preserving all upstream data
const input = $input.first().json;
return {
  json: {
    ...input,
    PERPLEXITY_API_KEY: process.env.PERPLEXITY_API_KEY,
    REDIS_PASSWORD: process.env.REDIS_PASSWORD,
  }
};
